"CONCAT(
  'INSERT INTO movies (title, genres, year, image_url, description) VALUES (',
  QUOTE(title), ',',
  QUOTE(genres), ',',
  COALESCE(year, 'NULL'), ',',
  QUOTE(COALESCE(image_url, '')), ',',
  QUOTE(COALESCE(description, '')),
  ');'
)"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Toy Story','Animation|Children|Comedy',1995,'https://image.tmdb.org/t/p/w500/y59d8PjuFSgJJN4VRS7jDoRgSM9.jpg','Los juguetes de Andy, un niño de seis años, temen que haya llegado su hora y que un nuevo regalo de cumpleaños les sustituya en el corazón de su dueño. Woody, un vaquero que ha sido hasta ahora el juguete favorito de Andy, trata de tranquilizarlos hasta que aparece Buzz Lightyear, un héroe espacial dotado de todo tipo de avances tecnológicos. Woody es relegado a un segundo plano, pero su constante rivalidad se transformará en una gran amistad cuando ambos se pierden en la ciudad sin saber cómo volver a casa.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Jumanji','Adventure|Children|Fantasy',1995,'https://image.tmdb.org/t/p/w500/m67M2wXLKblJLuJlvF7qaGrGfCa.jpg','Cuando el joven Alan Parrish descubre un misterioso juego de mesa, no se da cuenta de sus inimaginables poderes hasta que, por arte de magia, es transportado ante los ojos de su amiga Sarah a las salvajes junglas de Jumanji. Al cabo de 26 años, es liberado del juego por dos niños que no sospechan nada. Alan se reencuentra con Sarah y, junto a Judy y Peter, intentan burlar las poderosas fuerzas del juego antes de que sea demasiado tarde.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Lion King','Animation|Children|Drama|Musical',1994,'https://image.tmdb.org/t/p/w500/b0MxU37dNmMwKtoPVYPKOZSIrIn.jpg','La sabana africana es el escenario en el que tienen lugar las aventuras de Simba, un pequeño león que es el heredero del trono. Sin embargo, se ve forzado a exiliarse al ser injustamente acusado de la muerte de su padre. Durante su destierro, hará buenas amistades y, finalmente, regresará para recuperar lo que legítimamente le corresponde.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Pulp Fiction','Comedy|Crime|Drama|Thriller',1994,'https://image.tmdb.org/t/p/w500/hNcQAuquJxTxl2fJFs1R42DrWcf.jpg','Jules y Vincent, dos asesinos a sueldo con muy pocas luces, trabajan para Marsellus Wallace. Vincent le confiesa a Jules que Marsellus le ha pedido que cuide de Mia, su mujer. Jules le recomienda prudencia porque es muy peligroso sobrepasarse con la novia del jefe. Cuando llega la hora de trabajar, ambos deben ponerse manos a la obra. Su misión: recuperar un misterioso maletín.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Shawshank Redemption','Crime|Drama',1994,'https://image.tmdb.org/t/p/w500/uRRTV7p6l2ivtODWJVVAMRrwTn2.jpg','Acusado del asesinato de su mujer, Andrew Dufresne, tras ser condenado a cadena perpetua, es enviado a la prisión de Shawshank. Con el paso de los años conseguirá ganarse la confianza del director del centro y el respeto de sus compañeros presidiarios, especialmente de Red, el jefe de la mafia de los sobornos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Forrest Gump','Comedy|Drama|Romance|War',1994,'https://image.tmdb.org/t/p/w500/azV6hV99lYkdhydsQbJCI6FqMl4.jpg','Forrest Gump es un chico con deficiencias mentales no muy profundas y con alguna incapacidad motora que, a pesar de todo, llegará a convertirse, entre otras cosas, en un héroe durante la Guerra del Vietnam. Su persistencia y bondad le llevarán a conseguir una gran fortuna, ser objeto del clamor popular y a codearse con las más altas esferas sociales y políticas del país. Siempre sin olvidar a Jenny, su gran amor desde que era niño.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Matrix','Action|Sci-Fi|Thriller',1999,'https://image.tmdb.org/t/p/w500/8rT9kG2EYkZpJmYCuTJNnPDEube.jpg','Thomas Anderson lleva una doble vida: por el día es programador en una importante empresa de software, y por la noche un hacker informático llamado Neo. Su vida no volverá a ser igual cuando unos misteriosos personajes le inviten a descubrir la respuesta a la pregunta que no le deja dormir: ¿qué es Matrix?');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Titanic','Drama|Romance',1997,'https://image.tmdb.org/t/p/w500/VMOt5scbGmBKDvkfHjZN6Ki54i.jpg','Jack, un joven artista, gana en una partida de cartas un pasaje para viajar a América en el Titanic, el transatlántico más grande y seguro jamás construido. A bordo conoce a Rose, una joven de una buena familia venida a menos que va a contraer un matrimonio de conveniencia con Cal, un millonario engreído a quien sólo interesa el prestigioso apellido de su prometida. Jack y Rose se enamoran, pero el prometido y la madre de ella ponen todo tipo de trabas a su relación. Mientras, el gigantesco y lujoso transatlántico se aproxima hacia un inmenso iceberg.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Goodfellas','Crime|Drama',1990,'https://image.tmdb.org/t/p/w500/3Yy0zBO9AlyAZH1cTI8Ko2ouCi.jpg','Henry, un niño de trece años de Brooklyn, vive fascinado con el mundo de los gángsters. Su sueño se hace realidad cuando entra a formar parte de la familia Pauline, dueña absoluta de la zona, que lo educan como un miembro más de la banda convirtiéndole en un destacado mafioso.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Schindler\'s List','Drama|War',1993,'https://image.tmdb.org/t/p/w500/3Ho0pXsnMxpGJWqdOi0KDNdaTkT.jpg','Oskar Schindler, un hombre de enorme astucia y talento para las relaciones públicas, organiza un ambicioso plan para ganarse la simpatía de los nazis. Después de la invasión de Polonia por los alemanes, consigue, gracias a sus relaciones con los nazis, la propiedad de una fábrica de Cracovia. Allí emplea a cientos de operarios judíos, cuya explotación le hace prosperar rápidamente. Su gerente, también judío, es el verdadero director en la sombra, pues Schindler no tiene el menor conocimiento industrial.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Star Wars: Episode IV','Action|Adventure|Sci-Fi',1977,'https://image.tmdb.org/t/p/w500/ahT4ObS7XKedQkOSpGr1wQ97aKA.jpg','La princesa Leia, líder del movimiento rebelde que desea reinstaurar la República en la galaxia en los tiempos ominosos del Imperio, es capturada por las malévolas Fuerzas Imperiales, capitaneadas por el implacable Darth Vader, el sirviente más fiel del emperador. El intrépido Luke Skywalker, ayudado por Han Solo, capitán de la nave espacial "El Halcón Milenario", y los androides, R2D2 y C3PO, serán los encargados de luchar contra el enemigo y rescatar a la princesa para volver a instaurar la justicia en el seno de la Galaxia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Inception','Action|Crime|Drama|Mystery|Sci-Fi|Thriller',2010,'https://image.tmdb.org/t/p/w500/tXQvtRWfkUUnWJAn2tN3jERIUG.jpg','Dom Cobb es un ladrón hábil, el mejor de todos, especializado en el peligroso arte de extracción: el robo de secretos valiosos desde las profundidades del subconsciente durante el estado de sueño cuando la mente está más vulnerable. Esta habilidad excepcional de Cobb le ha hecho un jugador codiciado en el traicionero nuevo mundo de espionaje corporativo, pero al mismo tiempo, le ha convertido en un fugitivo internacional y ha tenido que sacrificar todo que le importaba. Ahora a Cobb se le ofrece una oportunidad para redimirse. Con un último trabajo podría recuperar su vida anterior, pero solamente si logra lo imposible.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Dark Knight','Action|Crime|Drama|IMAX',2008,'https://image.tmdb.org/t/p/w500/8QDQExnfNFOtabLDKqfDQuHDsIg.jpg','Batman/Bruce Wayne regresa para continuar su guerra contra el crimen. Con la ayuda del teniente Jim Gordon y del Fiscal del Distrito Harvey Dent, Batman se propone destruir el crimen organizado en la ciudad de Gotham. El triunvirato demuestra su eficacia, pero, de repente, aparece Joker, un nuevo criminal que desencadena el caos y tiene aterrados a los ciudadanos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Interstellar','Sci-Fi|IMAX',2014,'https://image.tmdb.org/t/p/w500/9cTfZWP5TfdnmAjiD6ZBXWIJ7O9.jpg','Un grupo de exploradores hacen uso de un agujero de gusano recientemente descubierto para superar las limitaciones de los viajes espaciales tripulados y vencer las inmensas distancias que tiene un viaje interestelar.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Silence of the Lambs','Crime|Horror|Thriller',1991,'https://image.tmdb.org/t/p/w500/8FdQQ3cUCs9goEOr1qUFaHackoJ.jpg','Clarice Starling, del FBI, se aventura a una prisión de máxima seguridad para analizar el cerebro enfermo de Hannibal Lecter, un psiquiatra convertido en caníbal.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Avengers: Endgame','Action|Adventure|Sci-Fi',2019,'https://image.tmdb.org/t/p/w500/br6krBFpaYmCSglLBWRuhui7tPc.jpg','Tras el chasquido de Thanos que eliminó a la mitad de la vida en el universo, los Vengadores supervivientes quedan devastados y divididos. Cinco años después, una inesperada oportunidad les permite intentar revertir la catástrofe. Reuniéndose una vez más, los héroes emprenden una misión extrema que los obliga a viajar al pasado, enfrentarse a sus propias pérdidas y hacer sacrificios definitivos para restaurar el equilibrio del universo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Spirited Away','Animation|Adventure|Fantasy',2001,'https://image.tmdb.org/t/p/w500/2RcxjDykOssx4SfqshewyI9vfSl.jpg','Durante el traslado de su familia a los suburbios, una niña de 10 años de edad deambula por un mundo gobernado por dioses, brujas y espíritus, y donde los humanos se convierten en bestias.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Godfather','Crime|Drama',1972,'https://image.tmdb.org/t/p/w500/ApiEfzSkrqS4m1L5a2GwWXzIiAs.jpg','Don Vito Corleone, conocido dentro de los círculos del hampa como \'El Padrino\', es el patriarca de una de las cinco familias que ejercen el mando de la Cosa Nostra en Nueva York en los años cuarenta. Don Corleone tiene cuatro hijos: una chica, Connie, y tres varones; Sonny, Michael y Fredo. Cuando el Padrino reclina intervenir en el negocio de estupefacientes, empieza una cruenta lucha de violentos episodios entre las distintas familias del crimen organizado.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Coco','Animation|Adventure|Children|Comedy|Fantasy|Musical|Mystery',2017,'https://image.tmdb.org/t/p/w500/vwsFGblLYxWBNjg9pdWN1Mm5YfW.jpg','Un joven aspirante a músico llamado Miguel se embarca en un viaje extraordinario a la mágica tierra de sus ancestros. Allí, el encantador embaucador Héctor se convierte en su inesperado amigo y le ayuda a descubrir los misterios detrás de las historias y tradiciones de su familia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Get Out','Horror|Mystery|Thriller',2017,'https://image.tmdb.org/t/p/w500/xiMoqa0bmjuyuXYqKGwrTSJL8nI.jpg','Un joven afroamericano visita a la familia de su novia blanca, un matrimonio adinerado. Para Chris y su novia Rose ha llegado el momento de conocer a los futuros suegros, por lo que ella le invita a pasar un fin de semana en el campo con sus padres, Missy y Dean. Al principio, Chris piensa que el comportamiento \'demasiado\' complaciente de los padres se debe a su nerviosismo por la relación interracial de su hija, pero a medida que pasan las horas, una serie de descubrimientos cada vez más inquietantes le llevan a descubrir una verdad inimaginable.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Punisher: One Last Kill','Action|Drama|Crime',2026,'https://image.tmdb.org/t/p/w500/p1eqHRxfIxfgtDgfjWcpEESeEvF.jpg','Mientras Frank Castle busca propósito más allá de la venganza, una fuerza inesperada lo arrastra de nuevo a la lucha.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Proyecto Salvación','Sci-Fi|Adventure',2026,'https://image.tmdb.org/t/p/w500/fj1FAiS6OHidg1O1T6z2356fD6u.jpg','El profesor de ciencias Ryland Grace se despierta en una nave espacial a años luz de casa sin recordar quién es ni cómo ha llegado hasta allí. A medida que recupera la memoria, empieza a descubrir su misión: resolver el enigma de la misteriosa sustancia que provoca la extinción del sol. Deberá recurrir a sus conocimientos científicos y a sus ideas poco ortodoxas para salvar todo lo que hay en la Tierra de la extinción... pero una amistad inesperada significa que quizá no tenga que hacerlo solo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Intercambiados','Animation|Family|Adventure|Fantasy',2026,'https://image.tmdb.org/t/p/w500/i89vUDwNhAEWUZSFYITSiv1RIbK.jpg','Una pequeña criatura del bosque intercambia el cuerpo con un majestuoso pájaro del valle, lo que los obliga a colaborar para sobrevivir a la aventura más salvaje de sus vidas.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Super Mario Galaxy la película','Family|Comedy|Adventure|Fantasy|Animation',2026,'https://image.tmdb.org/t/p/w500/cyrJXK2w5JMV1fpoOnkH17sjUBk.jpg','Secuela de \'Super Mario Bros: La película\', basada en la saga \'Mario Galaxy\'. Los hermanos Mario y Luigi y la princesa Peach emprenden una aventura hasta los confines del espacio y a través de la galaxia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El diablo viste de Prada','Drama|Comedy',2006,'https://image.tmdb.org/t/p/w500/y0FiGt44M7rveQYnYkIO3UttbTP.jpg','En el vertiginoso mundo de la moda en Nueva York, la revista \'Runway\' es el Santo Grial. Dirigida con puño de hierro y elegante manicura por Miranda Priestly, trabajar en ella es un temible reto para todo aquel que quiera triunfar en ese mundo. Hacerlo como ayudante de Miranda podría abrirle cualquier puerta a Andy Sachs, recientemente graduada. Pero ella es una chica que destaca por su desaliño dentro del pequeño ejército de guapísimas redactoras de la revista. Andy comprende muy pronto que para triunfar en ese negocio va a necesitar algo más que iniciativa y determinación. Y la prueba definitiva está delante de ella, vestida de Prada de pies a cabeza.  Es una mierda de película!!');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Depredador dominante','Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/mV7uFS1U8iP0p4CcXZp4znBVpch.jpg','Una mujer en duelo se adentra en la naturaleza de Australia para ponerse a prueba y queda atrapada en un juego mortal con un astuto asesino que la considera su presa.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Tu corazón se romperá','Romance|Drama',2026,'https://image.tmdb.org/t/p/w500/iGpMm603GUKH2SiXB2S5m4sZ17t.jpg','Polina, una estudiante de secundaria, encuentra un salvavidas inesperado frente al acoso que sufre en su nuevo instituto. Para frenar el bullying, sella un pacto con Bars, el cabecilla de los abusadores: él fingirá ser su novio y se convertirá en su protector, pero a cambio, ella tendrá que obedecerle en todo lo que él le pida.  Lo que empieza como un juego de supervivencia se complica cuando la química entre los dos se vuelve real. Sin embargo, su historia tiene los días contados: tanto sus familias como sus propios compañeros harán lo imposible por dinamitar una relación que nadie aprueba.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Sangre asesina','Action|Drama|Romance',2026,'https://image.tmdb.org/t/p/w500/16TvbhCP8CfiGEbxcbtQLYWO6WG.jpg','A una mujer le espera una bala con su nombre por culpa de su extraño grupo sanguíneo, pero encuentra cobijo en los brazos del asesino al que ama, y juntos luchan por sobrevivir.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Rita','Drama',2024,'https://image.tmdb.org/t/p/w500/grIFQLXXwQmjvYYfXVXCgGTMUWw.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mortal Kombat','Action|Fantasy|Adventure',2021,'https://image.tmdb.org/t/p/w500/2acqTZDykiX8U4oDVBIsNcm5O2o.jpg','Un boxeador fracasado descubre un secreto familiar que lo lleva a un torneo místico llamado Mortal Kombat donde se encuentra con un grupo de guerreros que luchan hasta la muerte para salvar los reinos del malvado hechicero Shang Tsung.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Tayuan 2','Drama',2026,'https://image.tmdb.org/t/p/w500/gkHNa8q3RNhgj2EMuoYWJUHsMa6.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Avatar: Fuego y ceniza','Sci-Fi|Adventure|Fantasy',2025,'https://image.tmdb.org/t/p/w500/4n1U0Mwn7djux6VKNYDRWPgS2x6.jpg','Jake Sully y Neytiri enfrentan una nueva amenaza en Pandora: los Ash People, una tribu Na\'vi violenta y sedienta de poder, liderada por la implacable Varang. Tras la devastadora guerra contra la RDA y la pérdida de su hijo mayor, la familia de Jake deberá luchar por su supervivencia y el futuro de Pandora en un conflicto que llevará a los personajes a sus límites emocionales y físicos. Con nuevos y antiguos aliados, esta épica visual y emocional redefine el destino de un mundo al borde del abismo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mortal Game','Horror|Action',2025,'https://image.tmdb.org/t/p/w500/iCvucorbs3hFqWshDbLe0fHzB71.jpg','Un grupo de cazadores viaja a una isla remota para rastrear a una criatura legendaria. Al descubrir que su guía los ha traicionado para usarlos como carnada, quedan atrapados y a merced de un depredador inteligente que los acecha uno a uno.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Noche de bodas 2','Thriller|Horror|Comedy',2026,'https://image.tmdb.org/t/p/w500/nDXKMOLJuBUKhYmHAY9qJdikuAq.jpg','Momentos después de sobrevivir a un ataque de la familia Le Domas, Grace descubre que ha alcanzado el siguiente nivel del juego, y esta vez acompañada por su hermana Faith, con quien mantiene una relación distante. Grace tiene una oportunidad para sobrevivir, mantener con vida a su hermana y reclamar el Alto Trono del Consejo que controla el mundo. Cuatro familias rivales la persiguen para hacerse con el trono, y quien gane lo gobernará todo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Beast (La bestia)','Action|Drama',2026,'https://image.tmdb.org/t/p/w500/3S32pzyZMoOJ3ADrnT2GbV4tiX4.jpg','Con la ayuda de su antiguo entrenador, un campeón de MMA retirado e invicto regresa a la jaula para vengar la muerte de su hermano y resolver sus problemas financieros.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Obsesión','Horror',2026,'https://image.tmdb.org/t/p/w500/rmCkNtzYR2xTOO3ZXmIqB5zgYdE.jpg','El anhelo romántico desesperado de un chico por su amor platónico de toda la vida desencadena un siniestro hechizo: Niki se vuelve irracionalmente obsesiva hasta convertirse en la sombra de Bear. Una fantasía aparentemente inofensiva que se convertirá en una perturbadora pesadilla.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Hoppers','Adventure|Animation|Comedy|Family|Sci-Fi',2026,'https://image.tmdb.org/t/p/w500/4Z0E1W7YvQ0aVtgj7KKtktb9ukd.jpg','Una amante de los animales aprovecha la oportunidad de utilizar una tecnología que coloca su conciencia en un castor robótico, descubriendo misterios dentro del mundo animal que van más allá de lo que podría haber imaginado.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mortal Kombat II','Action|Fantasy|Adventure',2026,'https://image.tmdb.org/t/p/w500/ivVKHht5jutNGnObn1y5sSDrAXn.jpg','Los campeones favoritos de los fans, ahora acompañados por el propio Johnny Cage, se enfrentan cara a cara en la definitiva y sangrienta batalla a muerte para vencer al oscuro régimen de Shao Kahn, que amenaza la existencia del Reino de la Tierra y a sus defensores.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Michael','Musical|Drama',2026,'https://image.tmdb.org/t/p/w500/2uK36ujoDXOfNiJ5Yp3raVprB51.jpg','El viaje de Michael Jackson más allá de la música, desde el descubrimiento de su extraordinario talento como líder de los Jackson Five hasta convertirse en una visionaria estrella cuya ambición creativa despertó un incansable afán por consagrarse como el mayor icono de la industria del entretenimiento.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Criaturas luminosas','Drama|Mystery',2026,'https://image.tmdb.org/t/p/w500/aNixJoh0U4kN85YM6vPyVZL6ALF.jpg','En este drama, basado en el bestseller homónimo, una viuda forja un vínculo con un pulpo muy listo y un joven a la deriva mientras trabaja de noche en un pequeño acuario.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Nymphomaniac. Volumen 2','Drama|Mystery',2013,'https://image.tmdb.org/t/p/w500/bx6iyY3uf1Wn3wUNEFnvAGe5sgW.jpg','Historia de una ninfómana contada por ella misma. Una fría noche invernal, un viejo solterón encuentra en un callejón a una joven herida y casi inconsciente. Después de recogerla y cuidarla, siente curiosidad por saber cómo pudo haber llegado a semejante situación; escucha atentamente el relato que ella hace de su vida, una vida llena de conflictos y turbias relaciones.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('GOAT: Como cabras','Animation|Comedy|Family',2026,'https://image.tmdb.org/t/p/w500/l8Y8o3RpFg54gmQQ8GVaxVroFmY.jpg','Will es una pequeña cabra con grandes sueños que recibe una oportunidad única en la vida para unirse a los profesionales y jugar al rugebol, un deporte de alta intensidad, mixto y de contacto total dominado por los animales más rápidos y feroces del mundo. A los nuevos compañeros de equipo de Will no les entusiasma tener a una cabrita en su plantilla, pero Will está decidido a revolucionar el deporte y demostrar de una vez por todas que «¡los pequeños saben jugar!».');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Escuadrón letal','Action|Crime|Drama|Thriller',2025,'https://image.tmdb.org/t/p/w500/ftBCLqEhDvgKRcux0fk5TriVhMD.jpg','Unos astutos y traicioneros ladrones desafian a la Policía Judicial de Macao. La Policía, que se encontraba en una dura batalla, invita de nuevo al experto en rastreo Huang De Zhong, retirado desde hace muchos años, a unir fuerzas con la joven élite del Departamento de Investigación Criminal de la Policía Judicial. Bajo la colisión de las técnicas tradicionales de rastreo y la alta tecnología, la policía y los criminales luchan con ingenio y valentía, y se lanzan a un duelo entre el bien y el mal parecido al juego del gato y el ratón.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Faces of Death','Horror',2026,'https://image.tmdb.org/t/p/w500/glKgsnUSBAb1IRBE7nwmBi6y3P4.jpg','Una mujer, empleada como moderadora de contenido de un sitio web, se encuentra con una serie de vídeos violentos que reproducen escenas de muerte de una película.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Las ovejas detectives','Comedy|Family|Mystery',2026,'https://image.tmdb.org/t/p/w500/kMJ4h39xe1fEzbLSt5FJCtEqb2H.jpg','Cada noche, un pastor lee en voz alta un asesinato misterioso, fingiendo que sus ovejas pueden entenderlo. Cuando lo encuentran muerto, las ovejas se dan cuenta enseguida de que ha sido un asesinato y creen saber cómo resolverlo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La leyenda de Aang: El último Airbender','Animation|Action|Adventure|Fantasy',2026,'https://image.tmdb.org/t/p/w500/iMsORWhD8MawINagL6kvpDVAtS.jpg','Película de animación que seguirá a Aang y sus amigos, ahora como jóvenes adultos, varios años después de los acontecimientos del final de \'Avatar: The Last Airbender\'.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Guardianes de la noche: Kimetsu no Yaiba La fortaleza infinita','Animation|Action|Fantasy',2025,'https://image.tmdb.org/t/p/w500/iWLV12z9oexSRLz2WKyqCZbKoPA.jpg','El Cuerpo de Cazadores de Demonios se enfrenta a los Doce Kizuki restantes antes de enfrentarse a Muzan en el Castillo del Infinito para derrotarlo de una vez por todas.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Zootrópolis 2','Adventure|Animation|Comedy|Family|Mystery',2025,'https://image.tmdb.org/t/p/w500/4fRdfQPjHiuDSkzaxFAV44k7Iem.jpg','Después de resolver el caso más importante en la historia de Zootrópolis, los policías novatos Judy Hopps y Nick Wilde descubren que su asociación no es tan sólida como pensaban cuando el Jefe Bogo les ordena unirse al programa de consejería "Compañeros en Crisis". Pero no pasa mucho tiempo para que su asociación se ponga a prueba al máximo, cuando la llegada de Gary, la serpiente, pone la ciudad patas arriba.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Venganza','Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/ggJGx8fwwy21gEIXYusIlHcUn8z.jpg','Carlos y Miguel son dos soldados de élite de las fuerzas especiales mexicanas y mejores amigos cuyas vidas cambian para siempre cuando Carlos es testigo del brutal asesinato de su esposa por manos de un despiadado asesino. Determinado a buscar justicia, emprende un peligroso viaje de venganza, alimentado por el dolor y armado con una lotería que cambia su vida.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La Obsesión de Kyla','Drama|Thriller|TV Movie',2018,'https://image.tmdb.org/t/p/w500/zHm5LtEOlmmMdgJDvADvUl90NlA.jpg','Riley conoce a Kyla en el instituto, una chica solitaria de la que rápidamente se vuelve amiga íntima. Pero pronto descubre la obsesión que tiene su nueva compañera.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Shelter: El Protector','Action|Crime|Thriller',2026,'https://image.tmdb.org/t/p/w500/kOsqd5jFZ0p3O8Z0k0VQvBW2neW.jpg','Un recluso en una remota isla escocesa rescata a una niña del mar, desencadenando una peligrosa secuencia de acontecimientos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('SEND HELP (Enviad ayuda)','Horror|Thriller|Comedy',2026,'https://image.tmdb.org/t/p/w500/qXZZtyzuTX3KMfSLssCR6J0mODd.jpg','Después de que un accidente de avión deje varados en una isla remota a una competente empleada y a su insoportable jefe, ella deberá utilizar sus habilidades de supervivencia para mantenerlos a ambos con vida, a pesar de su difícil relación.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Socias por accidente','Comedy|Romance|Family',2026,'https://image.tmdb.org/t/p/w500/sr1Yoj6XLPTWYcbDoBy67xivW4I.jpg','Alexa, una elegante relacionista pública, y Regina, una entrenadora de carácter fuerte y espíritu independiente, llevan vidas completamente opuestas hasta que un mismo hombre entra en su historia. Tras una coincidencia inesperada, ambas descubren que fueron engañadas por la misma persona y que sus caminos están más entrelazados de lo que imaginaban. Obligadas a unir fuerzas, Alexa y Regina pasarán de la desconfianza a una alianza improbable que pondrá a prueba sus diferencias, sus decisiones y su idea de lo que significa apoyarse entre mujeres.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Te van a matar','Action|Comedy|Horror',2026,'https://image.tmdb.org/t/p/w500/9dEn8a12dqkQw48zxQhPcpQ7D5W.jpg','Una mujer acepta un trabajo como ama de llaves en un rascacielos de Nueva York, sin conocer el historial de desapariciones del edificio. Pronto se da cuenta de que la comunidad está rodeada de misterio.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Graphic Desires','Thriller|Crime',2023,'https://image.tmdb.org/t/p/w500/fLHXk8eN7Rh2snjjB5KhEE9tqgo.jpg','Cuando el recluso Franklin engaña a su chica con una misteriosa mujer que conoce en una aplicación de citas, se convierte en el inicio de una obsesión mortal.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La guerra de los mundos','Sci-Fi|Thriller',2025,'https://image.tmdb.org/t/p/w500/fjgSlNGECNgVeMJaOdDAXmGh7ZM.jpg','Will Radford, un destacado analista de ciberseguridad, pasa sus días rastreando posibles amenazas a la seguridad nacional a través de un programa de vigilancia masiva. Un ataque de una entidad desconocida le lleva a cuestionarse si el gobierno le está ocultando algo a él... y al resto del mundo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Wormtown','Sci-Fi|Horror|Adventure',2025,'https://image.tmdb.org/t/p/w500/lE10ww38b7XA5LIagIsVQj9a8Hn.jpg','Un año después del inicio de una plaga de gusanos carnívoros que alteran la mente, la ciudad nocturna de Ashland, en Ohio, ha aceptado el dominio de los parásitos. Bajo el mando del alcalde Joshua, una figura casi sectaria, los fervientes «Ranchers» difunden su evangelio, ya sea por persuasión o por la fuerza. Un trío de mujeres no infectadas se aferra a la supervivencia mediante el rebusque, una higiene extrema y la evasión. Pero todo el mundo acaba cediendo, lo que desata la traición, el sacrilegio y el horror corporal.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Predator: Badlands','Action|Sci-Fi|Adventure',2025,'https://image.tmdb.org/t/p/w500/8nCEJ5hFJt0h8FhXafHGhEhT8d7.jpg','Un joven Predator rechazado por su clan encuentra un aliado inesperado en Thia y emprende un peligroso viaje en busca del adversario definitivo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Greenland 2','Adventure|Thriller|Sci-Fi',2026,'https://image.tmdb.org/t/p/w500/vPftEQkiMXzOEYfz1VjmERPcCa0.jpg','Después de sobrevivir al fin del mundo por la caída de un cometa, Jeff Garrity, junto con su mujer Allison y su hijo Nathan, deciden abandonar el búnker que les ha mantenido a salvo cinco años para buscar una zona en Europa que podría ser habitable. Así, el último refugio es el principio de un nuevo comienzo. Juntos emprenderán un viaje donde los desastres naturales y los humanos que sobrevivieron han convertido el mundo en un auténtico infierno.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El diablo viste de Prada 2','Comedy|Drama',2026,'https://image.tmdb.org/t/p/w500/sz687EF7yJMS4VNEdHKT9ebkhA9.jpg','Sigue la lucha de Miranda Priestly contra Emily Charlton, su ex asistente convertida en ejecutiva rival, mientras compiten por los ingresos por publicidad en medio de la decadencia de los medios impresos y Miranda se acerca a la jubilación.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Michael Jackson. La vida de un ídolo','Documentary|Musical',2011,'https://image.tmdb.org/t/p/w500/z2MFDKcgTI7vqYNIT3lEbNsdLAM.jpg','"Michael Jackson: La vida de un Ídolo" muestra la vida del cantante detrás de las cámaras, desde su infancia con los Jackson 5, pasando por su consagración como solista a nivel mundial y recordando los momentos previos a su repentina muerte en 2009. Dirigido por Andrew Eastel y producido por un amigo íntimo de la infancia de Michael Jackson, David Gest, “Michael Jackson: la vida de un ídolo” supone para Katherine Jackson la primera oportunidad de ofrecer su versión de la historia sobre su hijo: su infancia en Gary, su ciudad natal; su apoyo durante los juicios a los que se enfrentó Michael; y cómo salieron adelante tras estos capítulos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Hot Girls Wanted','Documentary',2015,'https://image.tmdb.org/t/p/w500/75ot83QOkc02vujyzmIbumQCU6Y.jpg','Gracias a Internet, miles de jóvenes estadounidenses están entrando en el “amateur” mundo del porno, en cumplimiento de una demanda creciente de aspirantes a estrellas estilo “chica de al lado”. ‘Hot Girls Wanted’ sigue a una de esas chicas, deseosa de dejar la vida de pueblo pequeño en busca de la libertad y la fama.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Apocalypto','Action|Drama|History',2006,'https://image.tmdb.org/t/p/w500/yQ4uC13IYVerbxMMXeSogSQUkOT.jpg','Historia ambientada en la época del imperio maya. Cuando la idílica existencia de los mayas es brutalmente interrumpida por el ataque de una fuerza invasora, un hombre emprende un arriesgado viaje a un mundo regido por el miedo y la opresión en el que le espera un incierto final. Debido a un giro del destino y espoleado por el amor a su esposa y a su familia, emprenderá el regreso a su hogar en un desesperado esfuerzo por preservar su forma de vida...');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Las malditas (Dollhouse)','Horror|Mystery',2025,'https://image.tmdb.org/t/p/w500/tvAJLf5E75oAULJvhOBALnUVxkO.jpg','Yoshie quedó destrozada tras la muerte accidental de su hija de cinco años. Para superar el dolor, compra una muñeca a la que peina y viste como a la niña, y el matrimonio la convierte en parte de la familia. Tras el nacimiento de otro bebé, la pareja recupera la ilusión y Yoshie olvida su obsesión por la muñeca, pero una serie de extraños sucesos parecen indicar que el juguete no está conforme con la llegada de una nueva criatura.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La asistenta','Mystery|Thriller',2025,'https://image.tmdb.org/t/p/w500/tMEu0gniT4zfcyDF5KMjof0DMog.jpg','Una joven (Sydney Sweeney), con un pasado complicado comienza a trabajar como asistenta en la lujosa casa de los Winchester. A medida que se adentra en la vida de la familia, descubrirá secretos oscuros que pondrán en peligro su seguridad, pero quizá ya sea demasiado tarde... Adaptación de la novela de Freida McFadden.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Brothers Under Fire','Action|Thriller|Mystery|Drama',2026,'https://image.tmdb.org/t/p/w500/e5EKqk9V7N3w0WvYFhl6wSVrMp0.jpg','El escuadrón del capitán Jordan Wright, de permiso para asistir a una boda en México, se topa con un cártel asesino. Mientras Jordan intenta poner a salvo a los supervivientes, estalla la guerra entre su escuadrón y el cártel, lo que le obliga a luchar para salvar a sus hombres.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('xXx','Action|Adventure|Thriller|Crime|Drama',2002,'https://image.tmdb.org/t/p/w500/gd4hRY3pFXRY7YVbMdVBpnKV7wC.jpg','Xander Cage es XXX, un antiguo ganador de X-Games y atleta profesional de deportes de extremo, que sobrevive vendiendo videos de sus increíbles hazañas, las cuales hacen emitir adrenalina por todo el cuerpo. Pero después de incontables encuentros con la ley, su mundo está a punto de tomar un rumbo aún más extremo... Porque Xander no sabe que ha sido "espiado" por Augustus Gibbons, un agente veterano de la Agencia Nacional de Seguridad que se encuentra en una desesperada situación en la distante ciudad de Praga, en donde su operativo secreto ha sido asesinado por una pandilla de mafiosos con un estilo muy propio, que se llaman así mismos Anarchy 99, encabezados por el brutal ex-Comandante del Ejército Ruso Yorgi.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Wellwood','Sci-Fi|Horror|Drama|Thriller',2025,'https://image.tmdb.org/t/p/w500/vRwzVKNHeeQ9srX6u2qsuflBozb.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Worldbreaker','Sci-Fi|Action|Horror',2025,'https://image.tmdb.org/t/p/w500/ahj1JU8r0uJv7QII5Uj7tKzbEsC.jpg','Un padre esconde a su hija en una isla para mantenerla a salvo mientras la equipa para la supervivencia y las batallas que se avecinan.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Ruta de escape','Crime|Thriller',2026,'https://image.tmdb.org/t/p/w500/oUF0tTmbwlfkhiYSU5nXJccr5K0.jpg','Davis es un escurridizo ladrón cuyos atracos de alto riesgo tienen desconcertada a la policía. Davis está planeando su mayor golpe, con la esperanza de que sea el último, cuando se cruza en su camino Sharon, una desilusionada ejecutiva de seguros con la que se ve obligado a trabajar, y Orman un ladrón rival, con métodos mucho más inquietantes que los de Davis. A medida que se acerca el golpe multimillonario, el implacable teniente Lubesnik, se acerca a la operación, aumentando considerablemente el riesgo de lo que está en juego y difuminando la línea entre cazador y presa. Pronto, cada uno tendrá que aceptar el coste de sus decisiones asumiendo que no hay vuelta atrás.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('911: Llamada infernal','Horror',2026,'https://image.tmdb.org/t/p/w500/aOIXYOwB97ioUnhHzwnyCRxwVBe.jpg','Durante una llamada rutinaria por disturbios domésticos, un trágico accidente lleva a dos oficiales de policía a una pesadilla implacable que revela la existencia de un culto aterrador.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Michael Jackson: Searching for Neverland','Drama|TV Movie',2017,'https://image.tmdb.org/t/p/w500/mRZIiG4vJiCgJh4v2EPUVVTznC8.jpg','Basado en el best-seller, Remember the Time: Protecting Michael Jackson in His Final Days, y contado a través de los ojos de los guardaespaldas de confianza de Jackson, Bill Whitfield y Javon Beard. La película revelará de primera mano la devoción que Michael Jackson tuvo por sus hijos y el drama oculto que tuvo lugar durante los últimos dos años de su vida.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Los Vengadores','Sci-Fi|Action|Adventure',2012,'https://image.tmdb.org/t/p/w500/ugX4WZJO3jEvTOerctAWJLinujo.jpg','Cuando un enemigo inesperado surge como una gran amenaza para la seguridad mundial, Nick Fury, director de la Agencia SHIELD, decide reclutar a un equipo para salvar al mundo de un desastre casi seguro.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Scream 7','Horror|Mystery|Crime',2026,'https://image.tmdb.org/t/p/w500/2pULHV2e3W7KNTyyfZl6dX071Np.jpg','Cuando un nuevo asesino Ghostface aparece en el tranquilo pueblo donde Sidney Prescott ha construido una nueva vida, sus peores miedos se hacen realidad cuando su hija se convierte en el siguiente objetivo. Decidida a proteger a su familia, Sidney debe enfrentarse a los horrores de su pasado para poner fin a la masacre de una vez por todas.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Cadena perpetua','Drama|Crime',1994,'https://image.tmdb.org/t/p/w500/uRRTV7p6l2ivtODWJVVAMRrwTn2.jpg','Acusado del asesinato de su mujer, Andrew Dufresne, tras ser condenado a cadena perpetua, es enviado a la prisión de Shawshank. Con el paso de los años conseguirá ganarse la confianza del director del centro y el respeto de sus compañeros presidiarios, especialmente de Red, el jefe de la mafia de los sobornos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Máquina de guerra','Action|Sci-Fi|Thriller',2026,'https://image.tmdb.org/t/p/w500/5C18uOTbDZRvVIZcVRO747k2fUi.jpg','En una última misión agotadora durante el entrenamiento para ser ranger, un ingeniero de combate debe liderar a su unidad contra una gigantesca máquina asesina de otro mundo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('美女奉行 おんな牢秘抄II','Drama|History',1995,'https://image.tmdb.org/t/p/w500/i3Ouy0rMUHyKeHZV3PYl106OSwe.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('给阿嬷的情书','Drama|Family',2026,'https://image.tmdb.org/t/p/w500/7OZB0IdMIohRd4BPyDZChOpzbrW.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Rise of the Conqueror','History|Action|Adventure|War',2026,'https://image.tmdb.org/t/p/w500/615WsMjiK76xBzW6zQNaPjgvnpP.jpg','Mientras el Imperio Mongol se desmorona, un guerrero marcado por la guerra enfrenta su destino y rompe lealtades para proteger el futuro de la Ruta de la Seda.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Crucifix: Blood of the Exorcist','Horror',2025,'https://image.tmdb.org/t/p/w500/iGDTo2uEUppEipTZjmEy6R72gwV.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Kraken','Horror|Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/8ExwomWgJoXBdY3u1Otiw2zY9wZ.jpg','Johanne es una bióloga marina que está investigando en una piscifactoría de Vangsnes, una comunidad rural situada junto al fiordo, cuando se topa con varios sucesos extraños. Junto con las brutales muertes de dos adolescentes de la localidad, todos los indicios apuntan al profundo fiordo. ¿Puede haber más en las profundidades de lo que el ojo puede ver? En el fondo del fiordo más profundo de Noruega descansa un monstruo mítico tan grande como una montaña, con una miríada de brazos dispuestos a aplastar y devorar todo lo que puedan agarrar.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Vacaciones para matar','Thriller|Action|Crime',1980,'https://image.tmdb.org/t/p/w500/q05X1TcL8ZHdGzznx7I8EjdYFnU.jpg','Un fugitivo trata de recuperar el botí­n de un robo que había escondido en una casa de montaña antes de ser detenido. Allí en lugar de pasar el fin de semana solos un matrimonio y la joven hermana de la mujer serán espiados a la espera de aprovechar la oportunidad idónea para recuperar los bienes robados, descubre sus secretos más morbosos antes de agredirlos para recuperar su botín.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La novia del año','Comedy|Romance|Family',2026,'https://image.tmdb.org/t/p/w500/4Y8HSuYIgKUum2JPfbkul3jR6jh.jpg','El sueño de Lienkie de formar su propia familia se hace añicos, así que trama un plan retorcido para ganar el premio a la «Novia del Año» y vengarse de su ex.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Cuando se acaba el porno 2','Documentary',2017,'https://image.tmdb.org/t/p/w500/eLYKLIIJDBhbXEtmagkHCcDt8eD.jpg','En esta secuela de After Porn Ends se entrevista a un nuevo grupo de ex-estrellas del porno para ser testigos de cómo son sus vidas después de abandonar la industria del cine para adultos. Entre las entrevistadas, leyendas del género como Ginger Lynn (Ten Little Maidens) o Georgina Spelvin (Devil in Miss Jones).');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Dhurandhar The Revenge','Action|Crime|Thriller',2026,'https://image.tmdb.org/t/p/w500/ov8vrRLZGoXHpYjSY9Vpv1tHJX7.jpg','Hamza Ali Mazari, cuya verdadera identidad es Jaskirat Singh Rangi, continúa su operación encubierta en el mundo criminal de Pakistán mientras rastrea a Majo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Insidious Inferno','Horror',2024,'https://image.tmdb.org/t/p/w500/8kljUAovBatZRYp2ye2RZr239hU.jpg','Una cabaña aislada está plagada de horribles asesinatos y, sin que los habitantes lo sepan, algo de otro mundo acecha en los pasillos. ¿Podrá la pareja resolver el misterio de los terrenos malditos a tiempo o abrirán la puerta al infierno?');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('버려진 청춘','Romance',1982,'https://image.tmdb.org/t/p/w500/2ty3Bx6ENkZlorh6NP6jzNcEUtL.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Sniper: En tierra de nadie','Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/hdSt80XqI2IWu9WOWZQVecuPT7D.jpg','Cuando el francotirador Brandon Beckett es tachado de terrorista, se ve obligado a desaparecer y embarcarse en una misión de rescate imposible junto a su legendario padre.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('After: Almas perdidas','Drama|Romance',2021,'https://image.tmdb.org/t/p/w500/cAvUp7ngPyuhx1nLjmCOTCBNo91.jpg','Cuando Tessa toma la decisión más importante de su vida, todo cambia. Los secretos que salen a la luz sobre su familia y la de Hardin ponen en peligro su relación y su futuro juntos. La vida de Tessa empieza a romperse en pedazos y ya nada será como antes. Aunque sabe que Hardin la quiere, estas dos almas perdidas están rodeadas de celos, odio... y perdón. Hasta ahora, el amor era suficiente para mantener su relación a flote, pero ¿de verdad sigue mereciendo la pena?');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Vengadores: Infinity War','Adventure|Action|Sci-Fi',2018,'https://image.tmdb.org/t/p/w500/ksBQ4oHQDdJwND8H90ay8CbMihU.jpg','El todopoderoso Thanos ha despertado con la promesa de arrasar con todo a su paso, portando el Guantelete del Infinito, que le confiere un poder incalculable. Los únicos capaces de pararle los pies son los Vengadores y el resto de superhéroes de la galaxia, que deberán estar dispuestos a sacrificarlo todo por un bien mayor. Capitán América e Ironman deberán limar sus diferencias, Black Panther apoyará con sus tropas desde Wakanda, Thor y los Guardianes de la Galaxia e incluso Spider-Man se unirán antes de que los planes de devastación y ruina pongan fin al universo. ¿Serán capaces de frenar el avance del titán del caos?');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Protector','Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/Awvlydvag364audeksfRFldVslq.jpg','La vida pacífica de Nikki, una exheroína de guerra, se ve destrozada cuando su hija es secuestrada. Inmersa en el submundo criminal mientras es perseguida por policías y militares, debe luchar para rescatar a su hija.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Balls Up: Con un par','Comedy|Action|Adventure',2026,'https://image.tmdb.org/t/p/w500/50V1E3NE3UDFmq0fhMpByx1b4Ka.jpg','Los ejecutivos de marketing Brad y Elijah lanzan un audaz patrocinio de preservativos de cobertura total directamente a la Copa del Mundo. Después de que su ebria celebración en Brasil desencadene un escándalo mundial, deberán huir de hinchas furiosos, delincuentes y funcionarios sedientos de poder para salvar sus carreras y volver a casa con vida.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Nymphomaniac. Volumen 1','Drama',2013,'https://image.tmdb.org/t/p/w500/y3pyIkcXMUv8ToIa3hShqKXDi8F.jpg','Historia de una ninfómana contada por ella misma. Una fría noche invernal, un viejo solterón (Stellan Skarsgård) encuentra en un callejón a una joven (Charlotte Gainsbourg) herida y casi inconsciente. Después de recogerla y cuidarla, siente curiosidad por saber cómo pudo haber llegado esa mujer a semejante situación; escucha atentamente el relato que ella hace de su vida, una vida llena de conflictos y turbias relaciones. Para su estreno comercial se dividirá en dos partes. Hay una versión completa de cinco horas y media que sólo se verá en ciertos actos culturales.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Expediente Warren: El último rito','Horror',2025,'https://image.tmdb.org/t/p/w500/qdoqogLNR6myoRrxYFxF4UTkFne.jpg','Los investigadores de lo paranormal Ed y Lorraine Warren se enfrentan a un último caso aterrador en el que están implicadas entidades misteriosas a las que deben enfrentarse.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Matrix','Action|Sci-Fi',1999,'https://image.tmdb.org/t/p/w500/8rT9kG2EYkZpJmYCuTJNnPDEube.jpg','Thomas Anderson lleva una doble vida: por el día es programador en una importante empresa de software, y por la noche un hacker informático llamado Neo. Su vida no volverá a ser igual cuando unos misteriosos personajes le inviten a descubrir la respuesta a la pregunta que no le deja dormir: ¿qué es Matrix?');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Super Mario Bros: La película','Family|Comedy|Adventure|Fantasy|Animation',2023,'https://image.tmdb.org/t/p/w500/5AIZhT8vwdut7ILImXk0bfRPbaX.jpg','Mientras trabajan en una avería subterránea, los fontaneros de Brooklyn, Mario y su hermano Luigi, viajan por una misteriosa tubería hasta un nuevo mundo mágico. Pero, cuando los hermanos se separan, Mario deberá emprender una épica misión para encontrar a Luigi. Con la ayuda del champiñón local Toad y unas cuantas nociones de combate de la guerrera líder del Reino Champiñón, la princesa Peach, Mario descubre todo el poder que alberga en su interior.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El padrino','Drama|Crime',1972,'https://image.tmdb.org/t/p/w500/ApiEfzSkrqS4m1L5a2GwWXzIiAs.jpg','Don Vito Corleone, conocido dentro de los círculos del hampa como \'El Padrino\', es el patriarca de una de las cinco familias que ejercen el mando de la Cosa Nostra en Nueva York en los años cuarenta. Don Corleone tiene cuatro hijos: una chica, Connie, y tres varones; Sonny, Michael y Fredo. Cuando el Padrino reclina intervenir en el negocio de estupefacientes, empieza una cruenta lucha de violentos episodios entre las distintas familias del crimen organizado.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('“Cumbres Borrascosas”','Romance|Drama',2026,'https://image.tmdb.org/t/p/w500/afGUJcMBJloAUp9uC27MQiqkD7X.jpg','Una audaz y original reinterpretación de una de una de las historias de amor más grandes de todos los tiempos, \'Cumbres Borrascosas\' de Emerald Fennell está protagonizada por Margot Robbie como Cathy y Jacob Elordi como Heathcliff, cuya pasión prohibida se transforma de romántica a intoxicante en una épica historia de lujuria, amor y locura.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Ahora me ves 3','Crime|Thriller',2025,'https://image.tmdb.org/t/p/w500/Aspr0HcItNVbgLC8cV0ZAO0EBcc.jpg','Los Cuatro Jinetes regresan junto a una nueva generación de ilusionistas en una extraordinaria aventura que contiene giros asombrosos, sorpresas alucinantes y trucos de magia nunca vistos en la gran pantalla.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El drama','Romance|Comedy|Drama',2026,'https://image.tmdb.org/t/p/w500/zgfBYGYCNcOZ51JDbr6tm45H8y0.jpg','Una pareja, en los días previos a su boda, se enfrenta a una crisis cuando unas inesperadas revelaciones desbaratan lo que uno de ellos creía saber sobre el otro.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('F1 la película','Action|Drama',2025,'https://image.tmdb.org/t/p/w500/wfpqaxoPKvcqzLy8FO0enGXBzU.jpg','El mítico piloto Sonny Hayes vuelve de su retiro, persuadido para liderar un equipo de Fórmula 1 en apuros y guiar a su joven promesa, en busca de una nueva oportunidad de éxito.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('¿Quieres ser mi novia?','Comedy|Romance',2026,'https://image.tmdb.org/t/p/w500/oscW8xV8EhRYj7iAhyVlBohKqxo.jpg','La relación de Javi y Lu enfrenta pruebas cuando surgen tentaciones: una joven con quien Javi tiene química, y un hombre maduro que persigue a Lu. Entre humor y enredos, su amor es puesto a prueba');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La doble vida de Miriam','Drama|TV Movie',2017,'https://image.tmdb.org/t/p/w500/kvcdaGcres9pGDwZfPN9jOKfZh.jpg','Cuando un cambio de circunstancias deja a Miriam incapaz de pagar sus estudios universitarios, toma una decisión sorprendente: comenzar a actuar en películas para adultos, usando el seudónimo Belle Knox. Miriam se encuentra con su familia y sus amigos en la escuela, manteniendo su doble vida en secreto. Pero pronto se difundieron rumores y Miriam se convirtió en el sujeto de ataques en línea viciosos y atención no deseada. Miriam responde: habla con los medios de comunicación, diciendo que su nueva línea de trabajo le da poder como feminista. Pero su postura confiada tiene consecuencias no deseadas. Miriam es rechazada por su familia conservadora y sus colegas en el mundo del cine adulto. Una decisión impulsiva ha salido rápidamente fuera de control y los problemas de Miriam apenas están comenzando.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La Odisea','Adventure|Action|Fantasy',2026,'https://image.tmdb.org/t/p/w500/f9J2BhE0W5ivcVEZ9zsv8HojvV5.jpg','Una epopeya mitológica que sigue la historia de Odiseo y su largo viaje a casa, de 10 años de duración, tras la guerra de Troya.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Las guerreras k-pop','Fantasy|Musical|Comedy|Animation',2025,'https://image.tmdb.org/t/p/w500/6EQMqEmdG5HoGe2zT1WwWUMvVhv.jpg','Cuando no están llenando estadios, las superestrellas del K-pop Rumi, Mira y Zoey usan sus poderes secretos para proteger a sus fans de una amenaza sobrenatural.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('28 años después: El templo de los huesos','Horror|Thriller|Sci-Fi',2026,'https://image.tmdb.org/t/p/w500/2DTPapravB7kVBWjm6RsqEWyNqn.jpg','El Dr. Kelson (Ralph Fiennes) se ve envuelto en una nueva y sorprendente relación, cuyas consecuencias podrían cambiar el mundo tal y como se conoce. Por otra parte, el encuentro de Spike (Alfie Williams) con el Gran Lord Jimmy Crystal (Jack O\'Connell) se convierte en una pesadilla de la que el chico no puede escapar. En este mundo, los infectados ya no son la mayor amenaza para la supervivencia, ya que la inhumanidad de los supervivientes puede ser aún más extraña y aterradora.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Origen','Action|Sci-Fi|Adventure',2010,'https://image.tmdb.org/t/p/w500/tXQvtRWfkUUnWJAn2tN3jERIUG.jpg','Dom Cobb es un ladrón hábil, el mejor de todos, especializado en el peligroso arte de extracción: el robo de secretos valiosos desde las profundidades del subconsciente durante el estado de sueño cuando la mente está más vulnerable. Esta habilidad excepcional de Cobb le ha hecho un jugador codiciado en el traicionero nuevo mundo de espionaje corporativo, pero al mismo tiempo, le ha convertido en un fugitivo internacional y ha tenido que sacrificar todo que le importaba. Ahora a Cobb se le ofrece una oportunidad para redimirse. Con un último trabajo podría recuperar su vida anterior, pero solamente si logra lo imposible.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Cannibal Mukbang','Horror|Comedy|Romance',2025,'https://image.tmdb.org/t/p/w500/f30neqyKxshsD9T5bCGenqVSkjf.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Top Gun: Maverick','Action|Drama',2022,'https://image.tmdb.org/t/p/w500/AlWpEpQq0RgZIXVHAHZtFhEvRgd.jpg','Después de más de 30 años de servicio como uno de los mejores aviadores de la Armada, Pete "Maverick" Mitchell se encuentra dónde siempre quiso estar, empujando los límites como un valiente piloto de prueba y esquivando el alcance en su rango, que no le dejaría volar emplazándolo en tierra. Cuando se encuentra entrenando a un destacamento de graduados de Top Gun para una misión especializada, Maverick se encuentra allí con el teniente Bradley Bradshaw, el hijo de su difunto amigo "Goose".');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Los hermanos demolición','Action|Comedy|Crime|Mystery',2026,'https://image.tmdb.org/t/p/w500/ttEESBvVrO8ngZr19qp6eBMVS9F.jpg','Un improbable dúo de hermanastros, uno un impulsivo detective y el otro un disciplinado, se ven atraídos por el asesinato de su padre en Hawai, lo que les lleva a un peligroso viaje para desenmascarar una conspiración de largo alcance.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mortal Kombat: Aniquilación','Action|Fantasy|Sci-Fi',1997,'https://image.tmdb.org/t/p/w500/wImgbIw8knn5WQvvqV5wdnIHdWn.jpg','Estamos en el universo del Emperador Shao-Khan, donde las reglas no existen y la vida es una continua batalla. Los esbirros del maquiavélico Khan han sido adiestrados para matar y están dispuestos a cumplir las órdenes de su amo, conseguir el control de la Tierra para iniciar su aniquilación total. Un héroe, llamado Liu Kang, les hará frente.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Regreso a Silent Hill','Mystery|Drama|Horror',2026,'https://image.tmdb.org/t/p/w500/giE8rc4RbFXAv10u3DyREXrN4QC.jpg','Impulsado por las sombras de su pasado, James Sunderland regresa a Silent Hill para encontrar a su amor perdido, Mary Crane. Pero el pequeño pueblo oscuro y deprimente ya no es el lugar de sus recuerdos. James se encuentra con personajes que le parecen demasiado familiares y que intentan distraerlo de su búsqueda de Mary. Cuanto más busca a Mary, más comienza a preguntarse si esto sigue siendo la realidad, o si ha caído en el oscuro inframundo de Jacob Crane.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Lindas y letales','Musical|Thriller|Action|Horror',2026,'https://image.tmdb.org/t/p/w500/cmZqxJQ9MdNQEoD49HYghOXsiwH.jpg','Un grupo de bailarinas lucha por sobrevivir mientras intentan escapar de una remota posada después de que su autobús se averíe de camino a una competición.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('En la zona gris','Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/yfgquGqeT6DtdsIzPPzTLRABBy0.jpg','Un equipo encubierto de agentes de élite viven en la sombra, tan cómodos manejando el poder y la influencia como armas automáticas y explosivos de gran potencia. Cuando un déspota roba una fortuna de mil millones de dólares, son enviados a recuperarla en lo que para cualquier otro sería una misión suicida. Lo que comienza como un atraco imposible empeora aún más y se convierte en una guerra total de estrategia, engaño y supervivencia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El caballero oscuro','Action|Crime|Thriller',2008,'https://image.tmdb.org/t/p/w500/8QDQExnfNFOtabLDKqfDQuHDsIg.jpg','Batman/Bruce Wayne regresa para continuar su guerra contra el crimen. Con la ayuda del teniente Jim Gordon y del Fiscal del Distrito Harvey Dent, Batman se propone destruir el crimen organizado en la ciudad de Gotham. El triunvirato demuestra su eficacia, pero, de repente, aparece Joker, un nuevo criminal que desencadena el caos y tiene aterrados a los ciudadanos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Moonwalker','Fantasy|Musical',1988,'https://image.tmdb.org/t/p/w500/3GwTPQkAcgDeAirRpEuJG8HDdRz.jpg','Michael, el héroe definitivo, se enfrenta con todas sus fuerzas al villano Mr. Big, cuya suprema ambición es apoderarse del mundo, logrando que los escolares consuman drogas. En el curso de esta terrible lucha, y mientras los seguidores de Mr. Big intentan eliminar a Michael, tres niños, Sean, Katie y Zake, son testigos de sus milagrosas transformaciones y su victoria final. Un cómic con estética videoclipera realizado a mayor gloria de la estrella del pop Michael Jackson, que se interpreta a sí mismo y que muestra aspectos de su vida, sus sueños y su música. Articulado a modo de Sketches, destaca el último de ellos que muestra a Jackson erigido en una especie de superhéroe galáctico que combate a las Fuerzas del Mal, episodio en el que aparece Joe Pesci y varios niños.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('This Is It','Musical|Documentary',2009,'https://image.tmdb.org/t/p/w500/a7nyJrfaI4lHyPDh4ptecylfqD7.jpg','Película documental realizado con el material grabado durante los últimos ensayos del "rey del pop" Michael Jackson, que preparaba su regreso a los escenarios cuando murió por una negligencia de su médico. La mayor parte del montaje del film fue rodado en junio de 2009 en el Staples Center de Los Ángeles y The Forum en Inglewood, en California, cuando Michael preparaba su \'This is it\', la serie de 50 conciertos que iba a ofrecer en el O2 Arena de Londres. Dirige el documental Kenny Ortega, responsable de los "High School Musical".');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Mortuary Assistant','Horror|Mystery',2026,'https://image.tmdb.org/t/p/w500/3loVbnQ9hmay4OA6QjV6yMpHRYf.jpg','Rebecca Owens, una licenciada en ciencias mortuorias, acepta un trabajo nocturno en la funeraria River Fields. Lo que comienza como un trabajo rutinario pronto se vuelve siniestro al enfrentarse a terroríficas fuerzas sobrenaturales.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El señor de los anillos: El retorno del rey','Adventure|Fantasy|Action',2003,'https://image.tmdb.org/t/p/w500/mWuFbQrXyLk2kMBKF9TUPtDwuPx.jpg','Las fuerzas de Saruman han sido destruidas, y su fortaleza sitiada. Ha llegado el momento de que se decida el destino de la Tierra Media, y por primera vez en mucho tiempo, parece que hay una pequeña esperanza. La atención del señor oscuro Sauron se centra ahora en Gondor, el último reducto de los hombres, y del cual Aragorn tendrá que reclamar el trono para ocupar su puesto de rey. Pero las fuerzas de Sauron ya se preparan para lanzar el último y definitivo ataque contra el reino de Gondor, la batalla que decidirá el destino de todos. Mientras tanto, Frodo y Sam continuan su camino hacia Mordor, a la espera de que Sauron no repare en que dos pequeños Hobbits se acercan cada día más al final de su camino, el Monte del Destino.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La fuerza del deber','Crime|Drama|Thriller',2026,'https://image.tmdb.org/t/p/w500/aPhwFUeaYV2hNswZ7N4kDJUYDeM.jpg','Con la seguridad de su familia en juego y rodeado de amenazas, un policía deberá decidir hasta dónde está dispuesto a llegar para cumplir con su deber.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Parásitos','Comedy|Thriller|Drama',2019,'https://image.tmdb.org/t/p/w500/4N55tgxDW0RRATyrZHbx0q9HUKv.jpg','Tanto Gi Taek (Song Kang-ho) como su familia están sin trabajo. Cuando su hijo mayor, Gi Woo (Choi Woo-sik), empieza a dar clases particulares en casa de Park (Lee Seon-gyun), las dos familias, que tienen mucho en común pese a pertenecer a dos mundos totalmente distintos, comienzan una interrelación de resultados imprevisibles.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Anaconda','Adventure|Comedy|Horror',2025,'https://image.tmdb.org/t/p/w500/zX1KJPiGTrzpFcjfOWlmqdRgpQd.jpg','Doug y Griff son muy buenos amigos desde que eran niños y siempre han soñado con hacer un remake de su película favorita de todos los tiempos: el «clásico cinematográfico» Anaconda. Cuando una crisis de mediana edad les anima a lanzarse por fin a la aventura, se adentran en la selva amazónica para empezar a rodar. Pero las cosas se ponen serias cuando aparece una anaconda gigante de verdad, convirtiendo su caótico y cómico plató de rodaje en una situación mortal.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El botín','Action|Thriller|Crime',2026,'https://image.tmdb.org/t/p/w500/55C5loKFkw7Cj0nMLWux4FJCRHI.jpg','El descubrimiento de varios millones de dólares en efectivo en un zulo abandonado de Miami quiebra la confianza de un grupo de policías. Ahora, todo y todos están bajo sospecha.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Robot salvaje','Family|Animation|Sci-Fi|Adventure',2024,'https://image.tmdb.org/t/p/w500/a0a7RC01aTa7pOnskgJb3mCD2Ba.jpg','Esta aventura épica cuenta la historia de una robot, Rozzum 7-1-3-4, "Roz" para abreviar, que naufraga en una isla inhabitada y debe aprender a adaptarse a los entornos rigurosos construyendo relaciones con los animales de la isla y convirtiéndose en la madre adoptiva de una cría de ganso huérfana.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Irreversible','Drama|Thriller|Crime',2002,'https://image.tmdb.org/t/p/w500/a6HvMOj2lVYnzqaNY6cX2hoCCXz.jpg','Irreversible. Porque el tiempo lo destruye todo. Porque algunos actos son irreparables. Porque el hombre es un animal. Porque el deseo de venganza es un impulso natural. Porque la mayoría de los crímenes quedan sin castigo. Porque la pérdida del amado destruye como un rayo. Porque el amor es el origen de la vida. Porque toda la historia se escribe con esperma y sangre. Porque las premoniciones no modifican el curso de los acontecimientos. Porque el tiempo lo revela todo: lo mejor y lo peor.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Secretary','Romance|Drama|Comedy',2002,'https://image.tmdb.org/t/p/w500/zCL29rCrHlTbiNjzY1f9tiAHJtF.jpg','Lee Holloway  tiene el peor de los currículum cuando decide solicitar un empleo de secretaria en el bufete de abogados de E. Edward Grey. Basta con decir que acaba de salir de una institución psiquiátrica y que, tan sólo un día después de volver a estar con su disfuncional familia de barrio periférico, ha recaído ya en su hábito secreto e inconfesable. Pese a que nunca en su vida ha tenido trabajo, Lee resulta finalmente contratada por el Sr. Grey, un misterioso abogado. Al principio el trabajo parece normal: mecanografiar cartas, archivar documentos y hacer el café; pero Lee y el Sr. Grey no tardan en embarcarse en una relación mucho más estrecha e íntima; una relación que haría sonrojar a cualquier jefe de personal.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Vengadores: Endgame','Adventure|Sci-Fi|Action',2019,'https://image.tmdb.org/t/p/w500/br6krBFpaYmCSglLBWRuhui7tPc.jpg','Tras el chasquido de Thanos que eliminó a la mitad de la vida en el universo, los Vengadores supervivientes quedan devastados y divididos. Cinco años después, una inesperada oportunidad les permite intentar revertir la catástrofe. Reuniéndose una vez más, los héroes emprenden una misión extrema que los obliga a viajar al pasado, enfrentarse a sus propias pérdidas y hacer sacrificios definitivos para restaurar el equilibrio del universo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La casa de la colina de paja','Thriller|Horror',1976,'https://image.tmdb.org/t/p/w500/7bEV13lR9QrVTpx7RVYk3ea1hkR.jpg','En lo alto de Straw Hill hay una casa de campo solitaria, una casa que pronto se estremecerá y temblará ante la violencia, lujuria e infidelidad que se desencadena en su interior.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El señor de los anillos: La comunidad del anillo','Adventure|Fantasy|Action',2001,'https://image.tmdb.org/t/p/w500/9xtH1RmAzQ0rrMBNUMXstb2s3er.jpg','En la Tierra Media, el Señor Oscuro Saurón creó los Grandes Anillos de Poder, forjados por los herreros Elfos. Tres para los reyes Elfos, siete para los Señores Enanos, y nueve para los Hombres Mortales. Secretamente, Saurón también forjó un anillo maestro, el Anillo Único, que contiene en sí el poder para esclavizar a toda la Tierra Media. Con la ayuda de un grupo de amigos y de valientes aliados, Frodo emprende un peligroso viaje con la misión de destruir el Anillo Único. Pero el Señor Oscuro Sauron, quien creara el Anillo, envía a sus servidores para perseguir al grupo. Si Sauron lograra recuperar el Anillo, sería el final de la Tierra Media.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Beekeeper: El protector','Action|Crime|Thriller',2024,'https://image.tmdb.org/t/p/w500/gBdhYoROX6SHE3vVnBfEHI7Ojma.jpg','La brutal campaña de venganza de Adam Clay adquiere tintes nacionales tras revelarse que es un antiguo agente de una poderosa organización clandestina conocida como "Beekeeper".');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Peligrosa obsesión','Drama',2014,'https://image.tmdb.org/t/p/w500/zMCeJiRbV7Z5TFA8JpALExAQra.jpg','En el verano de 1969, el coronel Kim Jin-pyeong, atrapado en un matrimonio sin amor con Lee Suk-jin, y Jong Ga-heun, la esposa chino-coreana del capitán Kyung Woo-jin, mantienen un apasionado romance secreto.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('โอมุคาเดะ','Horror|Thriller|War',2026,'https://image.tmdb.org/t/p/w500/7RdzEmKj2yy3DttYkvZ6G5cCtoE.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Joven y bonita','Drama',2013,'https://image.tmdb.org/t/p/w500/ga9B2AdWbB1YUwrSJHLwlA9l2Kx.jpg','\'Joven y bonita\' es un retrato de una joven de 17 años, interpretada por Marine Vacth (Ce que le jour doit à la nuit) a lo largo de cuatro largas temporadas con cuatro canciones como telón de fondo. Una historia narrada subjetivamente por la protagonista, una chica obsesionada con el sexo, la pasión y el deseo carnal hasta el punto de convertirlo en una forma de vida, que le atrapa en una espiral de lujuria de la que no puede escapar.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mike y Nick y Nick y Alice','Comedy|Sci-Fi|Crime',2026,'https://image.tmdb.org/t/p/w500/k6PSvLUs84QJsWLt0Zlkoa8ih6V.jpg','Dos gángsters y la mujer a la que aman intentan sobrevivir a la noche más peligrosa de sus vidas, en la que está implicada una máquina del tiempo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Jurassic World: El renacer','Sci-Fi|Adventure|Action',2025,'https://image.tmdb.org/t/p/w500/2sbGd7kDhMicDkT097FR9a2JyGU.jpg','Cinco años después de los eventos de "Dominion", la ecología del planeta ha demostrado ser insoportable para los dinosaurios, donde los pocos que quedan viven aislados en las regiones ecuatoriales. Zora Bennett es contratada para dirigir a un equipo de especialistas cuyo objetivo es conseguir el material genético de las tres criaturas más grandes, las cuales tienen en su ADN la clave para fabricar un medicamento que aportará grandes beneficios a la humanidad. Pero la operación se cruzará con una familia cuyo barco volcó y todos acabarán en una isla prohibida ocupada por dinosaurios de numerosas especies, donde tendrán que hacer lo imposible para sobrevivir.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Running Man','Action|Thriller|Sci-Fi',2025,'https://image.tmdb.org/t/p/w500/iw4akkBscNvCLJZIbMT3PTc7csP.jpg','En una América distópica en el año 2025, Ben Richards participa en el violento reality show "The Running Man" con el fin de ganar suficiente dinero para revivir a su hija gravemente enferma.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Drácula','Horror|Fantasy|Romance',2025,'https://image.tmdb.org/t/p/w500/ff7fyDdtXM2wu9jsm9gOMYtpvOl.jpg','Tras una devastadora pérdida, el príncipe Vlad II, conde Drácula (Caleb Landy Jones), renuncia a Dios y es maldecido a la vida eterna, condenado a vagar solitario a lo largo de los siglos. Este es el relato sobre la historia de amor jamás contada del infame vampiro, que desafiará al destino y la mortalidad en busca de su amor perdido.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Harry Potter y la piedra filosofal','Adventure|Fantasy',2001,'https://image.tmdb.org/t/p/w500/3MKK7vAJLtSkBTABMTjxf6TOCo3.jpg','Harry Potter es un huérfano que vive con sus desagradables tíos, los Dursley, y su repelente primo Dudley. Se acerca su undécimo cumpleaños y tiene pocas esperanzas de recibir algún regalo, ya que nunca nadie se acuerda de él. Sin embargo, pocos días antes de su cumpleaños, una serie de misteriosas cartas dirigidas a él y escritas con una estridente tinta verde rompen la monotonía de su vida: Harry es un mago y sus padres también lo eran.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El viaje de Chihiro','Animation|Family|Fantasy',2001,'https://image.tmdb.org/t/p/w500/2RcxjDykOssx4SfqshewyI9vfSl.jpg','Durante el traslado de su familia a los suburbios, una niña de 10 años de edad deambula por un mundo gobernado por dioses, brujas y espíritus, y donde los humanos se convierten en bestias.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La momia de Lee Cronin','Horror|Mystery',2026,'https://image.tmdb.org/t/p/w500/qlLsNgRUiPPEIVbcqZR2KmOBL7e.jpg','La joven hija de un periodista desaparece en el desierto sin dejar rastro—ocho años más tarde, la familia rota se conmociona cuando ella es devuelta a ellos, y lo que debiera haber sido una reunión jubilosa se convierte en una auténtica pesadilla.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Spider-Man: No Way Home','Action|Adventure|Sci-Fi',2021,'https://image.tmdb.org/t/p/w500/miZFgV81xG324rpUknQX8dtXuBl.jpg','Peter Parker es desenmascarado y por tanto no es capaz de separar su vida normal de los enormes riesgos que conlleva ser un súper héroe. Cuando pide ayuda a Doctor Strange, los riesgos pasan a ser aún más peligrosos, obligándole a descubrir lo que realmente significa ser Spider-Man.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('JUJUTSU KAISEN: Ejecución','Animation|Action|Fantasy',2025,'https://image.tmdb.org/t/p/w500/a4QuZ6oW71zCpwVW08u3fHBxc6E.jpg','Durante Halloween en Shibuya, un misterioso velo atrapa a la multitud dentro del distrito. Como consecuencia, diez colonias japonesas se convierten en zonas dominadas por maldiciones.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Culpa mía','Drama|Romance|Thriller',2023,'https://image.tmdb.org/t/p/w500/gp31EwMH5D2bftOjscwkgTmoLAB.jpg','Noah debe dejar su ciudad, novio y amigos para mudarse a la mansión de William Leister, el flamante y rico marido de su madre Rafaela. Por otro lado, con 17 años, orgullosa e independiente, Noah se resiste a vivir en una mansión rodeada de lujo. Allí conoce a Nick, su nuevo hermanastro, y el choque de sus fuertes personalidades se hace evidente desde el primer momento.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('The Christophers','Crime|Comedy',2026,'https://image.tmdb.org/t/p/w500/s6oUrGMNl8hVh7fn0O8oF2rHwrM.jpg','Los hijos de un artista antaño famoso contratan a una falsificadora para que complete unos lienzos inacabados y abandonados hace mucho tiempo, y así tener una herencia cuando él muera.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La caza','Action|Thriller|Horror',2020,'https://image.tmdb.org/t/p/w500/5WCuPRfa0h8jMT4Iu2jIIQXqllM.jpg','Doce extraños se despiertan en el claro de un bosque con muchas preguntas sin respuesta. ¿Dónde están? ¿Cómo llegaron allí? ¿Y por qué o con qué propósito están ahí? La respuesta a todas esas preguntas es: La caza, un juego macabro ideado por miembros de las élites globales, que se reúnen en un punto remoto o una casa para cazar humanos por diversión. Ellos son las presas; el resto, los cazadores. Pero todo está a punto de cambiar cuando Crystal, una de las jóvenes que se encuentra entre los "cazados", le da la vuelta al juego y empieza a inclinar la balanza a su favor. Uno a uno, comienza a deshacerse de los miembros de la élite que pretende darles caza, con la intención de llegar hasta la misteriosa mujer (Hilary Swank) que mueve los hilos de todo aquello.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Malèna','Drama',2000,'https://image.tmdb.org/t/p/w500/p1DmuHTnvhsWFvWX0xnMWrLBVZ5.jpg','Malena es la belleza más encantadora e irresistible de Castelcuto, un aburrido pueblo de la soleada costa siciliana. Es nueva en la población y estando su marido en la guerra, cada paseo que da por el pueblo se convierte en un espectáculo, acompañado por las lujuriosas miradas de los hombres de la localidad y de los resentidos cotilleos de sus envidiosas esposas. Un ejército de flacos adolescentes en bicicleta la sigue allí donde vaya, con la única intención de observar su exquisita y arquetípica belleza. Entre ellos se encuentra Renato Amoroso, un chico de trece años con mucha imaginación que lleva su deseo a unos límites inesperados de obsesiva fantasía.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Starbright','Adventure|Action',2026,'https://image.tmdb.org/t/p/w500/m1Zl07DNYeSyNcz9hf8hDsS2oB5.jpg','Una mujer encuentra el secreto para hacer realidad sus deseos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Shrek','Animation|Comedy|Fantasy|Adventure|Family',2001,'https://image.tmdb.org/t/p/w500/jTQONM7jt1yv2lL972TtmWO0UIZ.jpg','Hace mucho, mucho tiempo, en una lejanísima ciénaga vivía un intratable ogro llamado Shrek. Pero de repente, un día, su absoluta soledad se ve interrumpida por una invasión de sorprendentes personajes de cuento. Hay ratoncitos ciegos en su comida, un enorme y malísimo lobo en su cama, tres cerditos sin hogar y otros muchos seres increíbles que han sido deportados de su reino por el malvado Lord Farquaad. Para conseguir salvar su terreno, y de paso a sí mismo, Shrek hace un pacto con Farquaad y emprende viaje para conseguir que la preciosa princesa Fiona sea la novia del Lord. En tan importante misión le acompañan un burro chistoso, dispuesto a hacer cualquier cosa por Shrek. Todo, menos estarse calladito. Rescatar a la princesa de una dragona enamoradiza que suelta fuego al respirar va a resultar una tontería comparado con lo que ocurre cuando el oscuro secreto que la joven guardaba es revelado.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El árbol muy muy lejano','Family|Fantasy|Adventure',2026,'https://image.tmdb.org/t/p/w500/udXvLxC5gAqN8SinemyFBEcHpTf.jpg','Polly, Tim, y sus tres hijos son una familia moderna que se ve obligada a mudarse a la remota campiña inglesa. Poco después de su llegada, los niños descubren un árbol mágico y a sus extraordinarios y excéntricos habitantes.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Wardriver','Thriller|Crime',2026,'https://image.tmdb.org/t/p/w500/ipTXhWCJgeg5RN0CpmFZYDzOzQi.jpg','Un joven hacker es engañado para atracar la cuenta bancaria de una mujer desprevenida.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('വാഴ II','Comedy|Drama',2026,'https://image.tmdb.org/t/p/w500/1yLZ7kExd0UGGbaZW4LxmYD4OIf.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Seven','Crime|Mystery|Thriller',1995,'https://image.tmdb.org/t/p/w500/uVPcVz4b2hnSGrXYLdIGRXwcivs.jpg','El teniente Somerset, del departamento de homicidios, está a punto de jubilarse y ser reemplazado por el ambicioso y brillante detective David Mills. Ambos tendrán que colaborar en la resolución de una serie de asesinatos cometidos por un psicópata que toma como base la relación de los siete pecados capitales: gula, pereza, soberbia, avaricia, envidia, lujuria e ira. Los cuerpos de las víctimas, sobre los que el asesino se ensaña de manera impúdica, se convertirán para los policías en un enigma que les obligará a viajar al horror y la barbarie más absoluta.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Deadpool y Lobezno','Action|Comedy|Sci-Fi',2024,'https://image.tmdb.org/t/p/w500/9TFSqghEHrlBMRR63yTx80Orxva.jpg','Un apático Wade Wilson se afana en la vida civil tras dejar atrás sus días como Deadpool, un mercenario moralmente flexible. Pero cuando su mundo natal se enfrenta a una amenaza existencial, Wade debe volver a vestirse a regañadientes con un Lobezno aún más reacio a ayudar.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El club de la lucha','Drama|Thriller',1999,'https://image.tmdb.org/t/p/w500/sgTAWJFaB2kBvdQxRGabYFiQqEK.jpg','Un hombre consumido por el insomnio y una vida sin sentido conoce a Tyler Durden, un carismático anarquista que lo arrastra a un club secreto donde el dolor despierta algo dormido. Lo que comienza como liberación pronto se convierte en una guerra contra el sistema…');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Midnight Matinee','Horror|Mystery|Thriller|TV Movie',1988,'https://image.tmdb.org/t/p/w500/czam6wq46B9UCZvq85vicElckFq.jpg','A pesar de que un devastador asesinato tuvo lugar durante el festival de cine de terror de un pequeño pueblo dos años antes, la gente del pueblo quiere otro festival.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Del revés 2 (Inside Out 2)','Animation|Adventure|Comedy|Family',2024,'https://image.tmdb.org/t/p/w500/lE3DCRI7bQgHSiIuEPcFiXpiuGV.jpg','Riley entra en la adolescencia y el Cuartel General de su cabeza sufre una repentina reforma para hacerle hueco a algo totalmente inesperado propio de la pubertad: ¡nuevas emociones! Alegría, Tristeza, Ira, Miedo y Asco, con años de impecable gestión a sus espaldas (según ellos...) no saben muy bien qué sentir cuando aparece con enorme ímpetu Ansiedad. Y no viene sola: le acompañan envidia, vergüenza y aburrimiento.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Uykucu','Action|Thriller|Drama',2025,'https://image.tmdb.org/t/p/w500/xvycfI4PRusKfqvzmkb8xqO0g48.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('How to Have Sex','Drama',2023,'https://image.tmdb.org/t/p/w500/7GDdwWIxc8ainsb0TvC2AIEXTOz.jpg','Tres adolescentes británicas se van de vacaciones para celebrar sus ritos de iniciación: beber, salir de fiesta y ligar, en lo que debería ser el mejor verano de sus vidas.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('火遮眼','Action|Crime|Thriller',2026,'https://image.tmdb.org/t/p/w500/zP19YO60jwEsfKd5Qf1UvA5uJu8.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Los mundos de Coraline','Animation|Family|Fantasy',2009,'https://image.tmdb.org/t/p/w500/xz1HjxeqpIACyPtJMqv33Z2RjRP.jpg','Película de animación en la que se nos cuenta la historia de Coraline, una jovencita que descubre en su nueva casa una puerta secreta y decide abrirla. Al hacerlo, descubre una segunda versión de su vida, una vida paralela a la que ella tiene. A primera vista, la realidad paralela es curiosamente parecida a su vida de verdad, aunque mucho mejor. Pero cuando su increíble y maravillosa aventura empieza a tomar un cariz peligroso, su otra madre intenta mantenerla a su lado para siempre. Coraline deberá recurrir a su determinación y coraje, a la ayuda de los vecinos y a un gato negro con el don del habla para salvar a sus auténticos padres, a unos niños fantasmas y regresar a casa.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Los pecadores','Horror|Action|Thriller',2025,'https://image.tmdb.org/t/p/w500/zdClwqpYQXBSCGGDMdtvsuggwec.jpg','Tratando de dejar atrás sus problemáticas vidas, dos hermanos gemelos regresan a su pueblo natal para empezar de nuevo, solo para descubrir que un mal aún mayor les espera para darles la bienvenida.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Chainsaw Man - La película: El arco de Reze','Animation|Action|Romance|Fantasy',2025,'https://image.tmdb.org/t/p/w500/fJdnp5OO2wh07tdy6noACNyaqMJ.jpg','Denji trabajaba como cazador de demonios para la yakuza, tratando de saldar la deuda que había heredado de sus padres, pero la yakuza lo traicionó y lo mató. Antes de perder el conocimiento, Pochita, el perro-demonio motosierra de Denji, hizo un trato con él y le salvó la vida. Así se fusionaron, creando al imparable Chainsaw Man. Ahora, en medio de una brutal guerra entre demonios, cazadores y enemigos secretos, una misteriosa chica llamada Reze irrumpe en su mundo y Denji se enfrenta a su batalla más mortífera, impulsado por el amor, en un mundo donde la supervivencia no conoce reglas.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Noche de bodas','Horror|Comedy',2019,'https://image.tmdb.org/t/p/w500/47BlTRVQ43NyzgMWPLOkKYYnHez.jpg','Durante la noche de su boda, una mujer recibe la invitación por parte de la rica y excéntrica familia de su marido para participar en una tradición ancestral que se convierte en un juego letal de supervivencia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Donselya','Drama|Romance',2024,'https://image.tmdb.org/t/p/w500/iVS3ZiPsKy8Hhc5Dipqgrjmoj2b.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Strangers: Capítulo 3','Horror|Thriller',2026,'https://image.tmdb.org/t/p/w500/iKIg4RH3zUITuQ8RXKZhWH7rm4B.jpg','Los supervivientes se enfrentan a nuevas amenazas de extraños enmascarados. Secretos salen a la luz, poniendo en peligro sus vidas mientras la línea entre realidad y peligro se difumina en su lucha por sobrevivir. Tercera y última de la trilogía de películas basadas en "Los extraños" (2008)');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Superman','Sci-Fi|Adventure|Action',2025,'https://image.tmdb.org/t/p/w500/fvUJb08yatV2b3NUSwuYdQKYoFd.jpg','En un mundo que ha perdido la fe en la bondad, Superman lucha por reconciliar su herencia kryptoniana con los valores humanos que moldearon su carácter. Criado en la Tierra, representa la verdad, la justicia y el estilo americano, pero debe enfrentarse a un mundo cínico que cuestiona sus ideales. Entre el deber de proteger a la humanidad y la búsqueda de su identidad, Superman demuestra que la esperanza y la bondad nunca pasan de moda, incluso en los tiempos más oscuros, inspirando a otros a creer en un futuro mejor.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La guerra de las galaxias','Adventure|Action|Sci-Fi',1977,'https://image.tmdb.org/t/p/w500/ahT4ObS7XKedQkOSpGr1wQ97aKA.jpg','La princesa Leia, líder del movimiento rebelde que desea reinstaurar la República en la galaxia en los tiempos ominosos del Imperio, es capturada por las malévolas Fuerzas Imperiales, capitaneadas por el implacable Darth Vader, el sirviente más fiel del emperador. El intrépido Luke Skywalker, ayudado por Han Solo, capitán de la nave espacial "El Halcón Milenario", y los androides, R2D2 y C3PO, serán los encargados de luchar contra el enemigo y rescatar a la princesa para volver a instaurar la justicia en el seno de la Galaxia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El Susurro','Horror',2026,'https://image.tmdb.org/t/p/w500/x1kKY4OvlDGxTvBn5GDyTVCYv6.jpg','Lucía y Adrián huyen de su padre violento a una mansión. Descubren una red de snuff y una maldición familiar.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El abismo secreto','Romance|Sci-Fi|Thriller',2025,'https://image.tmdb.org/t/p/w500/3s0jkMh0YUhIeIeioH3kt2X4st4.jpg','Mandan a dos operativos de élite a vigilar lados opuestos de un misterioso abismo y allí intiman desde la distancia, pero deberán aunar fuerzas para sobrevivir al mal que esconde el abismo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Dusun Mayit','Adventure|Horror|Mystery',2025,'https://image.tmdb.org/t/p/w500/pkcOwMJXYAbjxEwO8rDTi8H9irL.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Your Name.','Animation|Romance|Drama',2016,'https://image.tmdb.org/t/p/w500/iaiy3tg9QVkDpObm1IGqmbC9A5C.jpg','Taki y Mitsuha descubren un día que durante el sueño sus cuerpos se intercambian, y comienzan a comunicarse por medio de notas. A medida que consiguen superar torpemente un reto tras otro, se va creando entre los dos un vínculo que poco a poco se convierte en algo más romántico.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Gary','Drama|Comedy',2026,'https://image.tmdb.org/t/p/w500/jtMuKwlOl4IzpB5fWn9RT9uyy6E.jpg','Dos amigos emprenden un viaje de trabajo, pero se topan con retos inesperados al intentar cumplir su misión. A medida que solucionan problemas y conectan con los lugareños, la experiencia les deja una huella imborrable y les ofrece una nueva perspectiva de su amistad.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Ne Zha 2','Animation|Action|Fantasy|Adventure',2025,'https://image.tmdb.org/t/p/w500/jz5sGlPGf0cWZ0uJPDc8cSjjFcZ.jpg','Cuando los cuerpos de los dos amigos, Aobing y Nezha, están a punto de ser destruidos, se les permite que sus almas sigan existiendo. Su maestro, Taiyi Zhenren, restaura sus cuerpos con la ayuda de una flor de loto. Después de esto, Nezha parte en busca de enfrentar al Rey Dragón del Mar del Este, Ao Guang.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Núremberg','History|Drama',2025,'https://image.tmdb.org/t/p/w500/5sIW7PmpnZDUoYGuw0HqEBbmzpa.jpg','Tras el fin de la II Guerra Mundial, con ocasión de los cruciales e inminentes juicios de Nuremberg contra el derrotado régimen Nazi, el psiquiatra estadounidense Douglas Kelley (Malek), encargado de determinar si los oficiales nazis prisioneros son aptos para ser juzgados por sus crímenes de guerra, se ve inmerso en una compleja batalla de ingenio dialéctico con Hermann Göring (Crowe), mano derecha de Hitler. Basada en el libro "El nazi y el psiquiatra", de Jack El-Hai.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Oppenheimer','Drama|History',2023,'https://image.tmdb.org/t/p/w500/ncKCQVXgk4BcQV6XbvesgZ2zLvZ.jpg','Película sobre el físico J. Robert Oppenheimer y su papel como desarrollador de la bomba atómica. Basada en el libro \'American Prometheus: The Triumph and Tragedy of J. Robert Oppenheimer\' de Kai Bird y Martin J. Sherwin.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Taboo: Family Secrets','Romance|Drama|Thriller',2024,'https://image.tmdb.org/t/p/w500/7BQR4LSk4cjuM0XTpMMGIPKGaa3.jpg','');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('¡La novia!','Sci-Fi|Horror|Fantasy',2026,'https://image.tmdb.org/t/p/w500/4xC5IfnCekweHkTFjqQsMOC1gca.jpg','En el Chicago de los años 30, Frankenstein pide ayuda al Dr. Euphronius para crear una compañera. Dan vida a una mujer asesinada como la Novia, lo que desencadena un romance, el interés de la policía y un cambio social radical.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Humint','Thriller|Action|Drama',2026,'https://image.tmdb.org/t/p/w500/3xI81SsZHRKY0ltVKbILbvU3wa4.jpg','Un agente surcoreano investiga una red de narcotráfico en Rusia y debe colaborar con un agente norcoreano, lo cual los lleva correr riesgos y descubrir secretos muy turbios.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Marty Supreme','Drama|Thriller',2025,'https://image.tmdb.org/t/p/w500/mijSU0Rws3tBBbhdE5udxPSaZvF.jpg','Biopic de Marty Reisman, un buscavidas convertido en campeón de ping pong, desde que empezó a jugar por apuestas en Manhattan hasta ganar 22 títulos importantes y convertirse en el más veterano en ganar una competición nacional de deportes de raqueta, con 67 años.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Spider-Man: Un nuevo día','Sci-Fi|Action|Adventure',2026,'https://image.tmdb.org/t/p/w500/ct7rSLY6OlQBETxQDzINzkhYIO2.jpg','Han pasado cuatro años desde los acontecimientos de No Way Home, y Peter Parker ahora es un adulto que vive completamente solo, ha desaparecido voluntariamente de las vidas y recuerdos de quienes ama. Combatiendo el crimen en una Nueva York que ya no conoce su nombre, se ha dedicado por completo a proteger su ciudad, pero a medida que aumentan las exigencias sobre él, la presión desencadena una evolución física que amenaza su existencia, al mismo tiempo que un extraño nuevo patrón de crímenes da lugar a una de las amenazas más poderosas a las que se ha enfrentado.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Avatar','Sci-Fi|Action|Adventure',2009,'https://image.tmdb.org/t/p/w500/t5T3LPbLLgP2OP6kloM9p2PXpJL.jpg','Año 2154. Jake Sully, un exmarine en silla de ruedas, es enviado al planeta Pandora, donde se ha creado el programa Avatar, gracias al cual los seres humanos pueden controlar de forma remota un cuerpo biológico con apariencia y genética de la especie nativa. Pronto se encontrará con la encrucijada entre seguir las órdenes de sus superiores o defender al mundo que le ha acogido y siente como suyo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Top Gun: Ídolos del aire','Action|Drama|Romance',1986,'https://image.tmdb.org/t/p/w500/W8QUPhiBOCdj2urJDzc2D9xdQb.jpg','La Marina de los Estados Unidos ha creado una escuela de élite para pilotos con el fin de sacar una promoción de expertos en técnicas de combate. En la academia, más conocida como Top Gun, a los mejores se les entrena para ser intrépidos y fríos al mismo tiempo, capaces de no perder los nervios en situaciones extremas y de no inmutarse al romper la barrera del sonido a los mandos de un F-14. A la escuela llega el joven Maverick, famoso por su temeraria aunque brillante forma de pilotar.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('No te olvidaré','Romance|Drama',2026,'https://image.tmdb.org/t/p/w500/iPJ4V6o5PttdBmHoehdOtWqQ6gx.jpg','Cuando los abuelos y tutores de Diem se niegan categóricamente a permitir que la vea, Kenna descubre una compasión inesperada seguida de un sentimiento más profundo y real con Ledger, exjugador de la NFL y propietario de un bar local. A medida que su romance secreto va cobrando forma, surgen problemas para los dos, lo que llevará a Kenna a una situación sentimental desoladora y, en último término, a reavivar la esperanza de una segunda oportunidad.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Embestida','Horror|Thriller',2026,'https://image.tmdb.org/t/p/w500/osYy4GDE4nr69MGTJxRaZlqU82S.jpg','Cuando un catastrófico huracán azota un pueblo costero, el nivel del mar sube rápidamente y sus habitantes deben sobrevivir a un montón de hambrientos tiburones.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Train to Busan','Horror|Thriller|Action|Adventure',2016,'https://image.tmdb.org/t/p/w500/anomz7b3GQtHPFH34SODDBBIUad.jpg','Un virus letal se expande por Corea del Sur, provocando violentos altercados. Los pasajeros de un tren KTX que viaja de Seúl a Busan tendrán que luchar por su supervivencia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Ted 2','Comedy|Fantasy',2015,'https://image.tmdb.org/t/p/w500/bO59Vn36fQauTDQpKNlHxvcK9Nw.jpg','Se trata de una secuela de la exitosa comedia escrita y dirigida por el cómico Seth MacFarlane. Recién casados Ted y Tami-Lynn deciden tener un bebé. John se ofrece en donar su esperma para que su mejor amigo pueda cumplir su sueño de tener un hijo, pero inesperadamente reciben una carta legal que dice que el estado no le permite ser padre ya que no está demostrado que sea una persona. Todos juntos tendrán que unir fuerzas para luchar por sus derechos en un tribunal de justicia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Dune: Parte dos','Sci-Fi|Adventure',2024,'https://image.tmdb.org/t/p/w500/xCHmhHeO7aOCMlzcNukGH6Q7EiD.jpg','Sigue el viaje mítico de Paul Atreides mientras se une a Chani y los Fremen en una guerra de venganza contra los conspiradores que destruyeron a su familia. Al enfrentarse a una elección entre el amor de su vida y el destino del universo conocido, Paul se esfuerza por evitar un futuro terrible que solo él puede prever.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Dune','Sci-Fi|Adventure',2021,'https://image.tmdb.org/t/p/w500/szcew6yyjcDvaL0isaPBk2e3nkF.jpg','En un lejano futuro, la galaxia conocida es gobernada mediante un sistema feudal de casas nobles bajo el mandato del Emperador. Las alianzas y la política giran entorno a un pequeño planeta, Dune,  del que extrae la \'especia melange\', la materia prima que permite los viajes espaciales. La Casa Atreides, bajo el mandato del Duque Leto Atreides recibe el encargo de custodiar el planeta, relevando en la encomienda a sus históricos enemigos, los Harkonnen. Paul Atreides, hijo del duque, se verá atrapado en las intrigas políticas mientras descubre el destino que le deparan los desiertos de Dune.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Hellfire','Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/tQti9QTf13MfzNpXguijgNh7ojE.jpg','Un hombre solitario llega a un pequeño pueblo y descubre que sus habitantes viven bajo el control de un líder cruel, así que decide intervenir para intentar liberarlos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Iron Man','Action|Sci-Fi|Adventure',2008,'https://image.tmdb.org/t/p/w500/tFCTNx7foAsUQpgu2x1KjAJD1wT.jpg','El multimillonario fabricante de armas Tony Stark debe enfrentarse a su turbio pasado después de sufrir un accidente con una de sus armas. Equipado con una armadura de última generación tecnológica, se convierte en \'El hombre de hierro\' para combatir el mal a escala global.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Alien, el octavo pasajero','Horror|Sci-Fi',1979,'https://image.tmdb.org/t/p/w500/pZ9cAe5FxexJjpCaeiETbXzz3Fs.jpg','De regreso a la Tierra, la nave de carga Nostromo interrumpe su viaje y despierta a sus siete tripulantes. El ordenador central, MADRE, ha detectado la misteriosa transmisión de una forma de vida desconocida, procedente de un planeta cercano aparentemente deshabitado. La nave se dirige entonces al extraño planeta para investigar el origen de la comunicación.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La milla verde','Fantasy|Drama|Crime',1999,'https://image.tmdb.org/t/p/w500/aBQiJRxGRrX0mXFMjxyzWYFtEnf.jpg','En el sur de los Estados Unidos, en plena Depresión, Paul Edgecomb es un vigilante penitenciario a cargo de la Milla Verde, un pasillo que separa las celdas de los reclusos condenados a la silla eléctrica. Esperando su ejecución está John Coffey, un gigantesco negro acusado de asesinar brutalmente a dos hermanas de nueve años. Tras una personalidad ingenua, Coffey esconde un don sobrenatural prodigioso. A medida que transcurre la historia, Paul Edgecomb aprende que los milagros ocurren... incluso en los lugares más insospechados.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Sin piedad','Sci-Fi|Action|Thriller',2026,'https://image.tmdb.org/t/p/w500/9zBNg8koM3fjUTPT7QeJHuGG2r9.jpg','En un futuro próximo, un detective (Chris Pratt) es acusado de asesinar a su esposa. Tiene 90 minutos para demostrar su inocencia ante la Jueza de la I.A. avanzada (Rebecca Ferguson), a la que él mismo defendió en su día, antes de que esta decida su destino.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El Padrino Parte II','Drama|Crime',1974,'https://image.tmdb.org/t/p/w500/mbry0W5PRylSUHsYzdiY2FSJwze.jpg','Continuación de la saga de los Corleone con dos historias paralelas: la elección de Michael Corleone como jefe de los negocios familiares y los orígenes del patriarca, el ya fallecido Don Vito, primero en Sicilia y luego en Estados Unidos, donde, empezando desde abajo, llegó a ser un poderosísimo jefe de la mafia de Nueva York.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Hasta el fondo: La historia de Pornhub','Documentary',2023,'https://image.tmdb.org/t/p/w500/uJldamB3Le1eELdjqaBd4APGU49.jpg','Este documental ofrece un análisis en profundidad de los éxitos y escándalos de Pornhub a través de entrevistas con artistas, activistas y antiguos empleados.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Zootrópolis','Animation|Adventure|Family|Comedy',2016,'https://image.tmdb.org/t/p/w500/4zIlT48TgNLuJpUtFOkFITHoCQE.jpg','La moderna metrópoli mamífera de Zootrópolis es una ciudad absolutamente única. Está compuesta de barrios con diferentes hábitats como la lujosa Plaza Sahara, el Distrito Selva Tropical y el gélido Distrito Tundra. Es un crisol donde los animales de cada entorno conviven, un lugar donde no importa lo que seas. De hecho puedes ser cualquier cosa, desde un elefante enorme hasta la musaraña más diminuta. Pero cuando llega la optimista agente Judy Hopps, descubre que ser la primera conejita de un cuerpo policial compuesto de animales duros y enormes no es nada fácil. Pero está decidida a demostrar su valía y se mete de cabeza en un caso, a pesar de que eso significa trabajar con Nick Wilde, un zorro parlanchín y estafador, para resolver el misterio.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mulán: Enciende el Fuego','Drama',2026,'https://image.tmdb.org/t/p/w500/9n0KWXmbnf2yJ3rPQLC1xuK52pk.jpg','Exsoldado Mulan regresa a su aldea y descubre que sus padres han sido asesinados y su hermano desaparecido. Al investigar, destapa una red de falsificación de moneda y corrupción oficial, pero es incriminada por el magistrado Ji Shixun, quien en realidad es el verdadero cerebro del complot. Tras sobrevivir a la persecución y perder a su hermano, Mulan regresa al combate, lidera una rebelión popular, derrota a los responsables y abandona su hogar para iniciar un nuevo viaje.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Mortal Kombat Legends: La venganza de Scorpion','Animation|Action|Fantasy',2020,'https://image.tmdb.org/t/p/w500/sqBl12v4AXVoc5PmeGnd8oZ7HHY.jpg','Basado en el popular videojuego creado por Ed Boon y John Tovias, Mortal Kombat Legends: Scorpion’s Revenge pone el foco en un torneo único que se celebra una vez por generación y en el que se enfrentan los campeones de distintos reinos. El ganador determinará el destino de la Tierra y de sus habitantes.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Barbie','Comedy|Adventure|Fantasy',2023,'https://image.tmdb.org/t/p/w500/fNtqD4BTFj0Bgo9lyoAtmNFzxHN.jpg','Barbie vive en Barbieland donde todo es ideal y lleno de música y color. Un buen día decide conocer el mundo real. Cuando el CEO de Mattel se entere, tratará de evitarlo a toda costa y devolver a Barbie a una caja.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Uno de los nuestros','Drama|Crime',1990,'https://image.tmdb.org/t/p/w500/3Yy0zBO9AlyAZH1cTI8Ko2ouCi.jpg','Henry, un niño de trece años de Brooklyn, vive fascinado con el mundo de los gángsters. Su sueño se hace realidad cuando entra a formar parte de la familia Pauline, dueña absoluta de la zona, que lo educan como un miembro más de la banda convirtiéndole en un destacado mafioso.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Misión: Imposible - Sentencia final','Action|Thriller|Adventure',2025,'https://image.tmdb.org/t/p/w500/mKK7cVNg4mQmKl0Qry9fvr5AqP7.jpg','El agente Ethan Hunt continúa su misión de impedir que Gabriel controle el tecnológicamente omnipotente programa de IA conocido como "the Entity".');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Vaiana 2','Adventure|Animation|Comedy|Family|Fantasy',2024,'https://image.tmdb.org/t/p/w500/bit1B5F7IQydiWqdwAAD8f9TkXs.jpg','Tras recibir una inesperada llamada de sus antepasados, Vaiana debe viajar a los lejanos mares de Oceanía y adentrarse en peligrosas aguas perdidas para vivir una aventura sin precedentes.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Spider-Man','Action|Sci-Fi',2002,'https://image.tmdb.org/t/p/w500/bCDaKZLRkrVVtPNyHxUfKvepW1N.jpg','Peter Parker es un joven y tímido estudiante que vive con su tía May y su tío Ben desde la muerte de sus padres. Un día es mordido por una araña que ha sido modificada genéticamente, descubriendo al día siguiente que posee unos poderes poco habituales: tiene la fuerza y agilidad de una araña.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Herida','Drama|Romance',1992,'https://image.tmdb.org/t/p/w500/vyvSlairapZNGUUYFhHbYl3Uw1I.jpg','Peligrosa aventura de amor y sexo entre un hombre maduro y la prometida de su hijo. Él es un respetable miembro del Parlamento, pero está dispuesto a dejarlo todo por ella; ella, calculadora y pragmática, está decidida a casarse con su novio.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Harry Potter y el prisionero de Azkaban','Adventure|Fantasy',2004,'https://image.tmdb.org/t/p/w500/wF9aoo4YZmpKP4bZPSy4Zwwek6G.jpg','Harry está deseando que termine el verano para comenzar un nuevo curso en Hogwarts, y abandonar lo antes posible la casa de sus despreciables tíos, los Dursley. Lo que desconoce Harry es que va a tener que abandonar Privet Drive antes de tiempo e inesperadamente después de convertir a su tía Marge en un globo gigante. Un autobús noctámbulo, y encantado por supuesto, le llevará a la taberna El Caldero Chorreante, donde le espera nada menos que Cornelius Fudge, el Ministro de Magia.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Marty, Life Is Short: El documental','Documentary',2026,'https://image.tmdb.org/t/p/w500/z4QdUukg4FnbcwM6qeP6ZCoQZhf.jpg','Martin Short repasa toda una vida llena de alegría en este documental con clips clásicos, entrevistas recientes y vídeos caseros inéditos repletos de celebridades.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Hunting Season','Action|Drama|Thriller',2025,'https://image.tmdb.org/t/p/w500/cbryTyaWdqrKpQCw6K7zm2jrB5v.jpg','Cuando una misteriosa joven aparece en la orilla de un río local, tanto la niña de doce años que la descubre como su sobreprotector padre cambian para siempre con la llegada de esta extraña a su hogar. Mientras, un despiadado capo de la droga no se detendrá ante nada para matarla de una vez por todas.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Indomable','Animation|Family|Fantasy|Adventure',2012,'https://image.tmdb.org/t/p/w500/cTouCa0ObuGD1P2nKOQ7A21wm9p.jpg','Mérida, la indómita hija del Rey Fergus y de la Reina Elinor, es una hábil arquera que decide romper con una antigua costumbre, que es sagrada para los señores de la tierra: el gigantesco Lord MacGuffin, el malhumorado Lord Macintosh y el cascarrabias Lord Dingwall. Las acciones de Merida desencadenan el caos y la furia en el reino. Además, pide ayuda a una sabia anciana que le concede un deseo muy desafortunado. La muchacha tendrá que afrontar grandes peligros antes de aprender qué es la auténtica valentía.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Deseo, peligro','Action|Drama|Romance|Thriller',2007,'https://image.tmdb.org/t/p/w500/xjPFFyy8hk5qKubWL3ysBSDTutL.jpg','Shanghai, 1942. La ciudad está ocupada por los japoneses. La señora Mak, una mujer rica y sofisticada, recuerda cómo empezó todo en 1938. Su verdadero nombre no es Mak, sino Wong Chia Chi. Poco antes de estallar la II Guerra Mundial (1939-1945), su padre huyó a Inglaterra y la dejó en China. Era estudiante universitaria y conoció a Kuang Yu Min, que acababa de fundar una compañía de teatro para fomentar el patriotismo. Wong Chia Chi se convirtió en la primera actriz de la compañía. Kuang, por su parte, convenció a un grupo de estudiantes para que asesinaran al señor Yee, un importante colaborador de los japoneses. Wong Chia Chi colaboró en el plan haciéndose pasar por la señora Mak: su cometido era hacerse amiga de la mujer de Yee para ganarse la confianza de éste y seducirlo. Todo iba sucediendo según lo previsto, hasta que se produjo un acontecimiento inesperado.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Monstruos, S.A.','Animation|Comedy|Family',2001,'https://image.tmdb.org/t/p/w500/g3SgHEb5ej2MioGfYLrZVshF909.jpg','Monsters Inc. es la mayor empresa de miedo del mundo, y James P. Sullivan es uno de sus mejores empleados. Asustar a los niños no es un trabajo fácil, ya que todos creen que los niños son tóxicos y no pueden tener contacto con ellos. Pero un día una niña se cuela sin querer en la empresa, provocando el caos.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Troya','War|Action|History',2004,'https://image.tmdb.org/t/p/w500/mBiDQT28DnuYaJSL4nDD43ORE6p.jpg','A lo largo de los tiempos, los hombres han hecho la guerra. Unos por poder, otros por gloria o por honor, y algunos por amor. En la antigua Grecia, la pasión de dos de los amantes más legendarios de la historia, Paris, príncipe de Troya y Helena, reina de Esparta, desencadena una guerra que asolará una civilización. El rapto de Helena por Paris, separándola de su esposo, el rey Menelao, es un insulto que El orgullo familiar establece que una afrenta a Menelao es una afrenta a su hermano Agamenón, el poderoso rey de Micenas, que no tarda en reunir a todas las grandes tribus de Grecia para recuperar a Helena de manos de los troyanos y defender el honor de su hermano. La verdad es que la lucha por el honor por parte de Agamenón está corrompida por su incontenible codicia ya que necesita conquistar Troya para asumir el control del mar Egeo.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('La lista de Schindler','Drama|History|War',1993,'https://image.tmdb.org/t/p/w500/3Ho0pXsnMxpGJWqdOi0KDNdaTkT.jpg','Oskar Schindler, un hombre de enorme astucia y talento para las relaciones públicas, organiza un ambicioso plan para ganarse la simpatía de los nazis. Después de la invasión de Polonia por los alemanes, consigue, gracias a sus relaciones con los nazis, la propiedad de una fábrica de Cracovia. Allí emplea a cientos de operarios judíos, cuya explotación le hace prosperar rápidamente. Su gerente, también judío, es el verdadero director en la sombra, pues Schindler no tiene el menor conocimiento industrial.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('Weapons','Horror|Mystery',2025,'https://image.tmdb.org/t/p/w500/nYqEQ3ltw0hHc1kBaNWr7Rb8WNZ.jpg','Cuando todos los alumnos de una misma clase, salvo uno, desaparecen misteriosamente la misma noche y exactamente a la misma hora, la pequeña ciudad donde viven se pregunta quién o qué está detrás de su desaparición.');"
"INSERT INTO movies (title, genres, year, image_url, description) VALUES ('El señor de los anillos: Las dos torres','Adventure|Fantasy|Action',2002,'https://image.tmdb.org/t/p/w500/up6gIHZlfEQZkHIfQwcOOaGOzOt.jpg','La Compañía del Anillo se ha disuelto. El portador del anillo Frodo y su fiel amigo Sam se dirigen hacia Mordor para destruir el Anillo Único y acabar con el poder de Sauron. Mientras, y tras la dura batalla contra los orcos donde cayó Boromir, el hombre Aragorn, el elfo Legolas y el enano Gimli intentan rescatar a los medianos Merry y Pipin, secuestrados por los ogros de Mordor. Por su parte, Saurón y el traidor Sarumán continúan con sus planes en Mordor, en espera de la guerra contra las razas libres de la Tierra Media.');"
